import type { LucideIcon } from "lucide-react";

export type Person = {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phone?: string;
  age: number;
  gender: PersonGender;
  department: PersonDepartment;
  position: string;
  salary: number;
  startDate: Date;
  endDate?: Date;
  isActive: boolean;
  skills?: PersonSkill[];
  location: PersonLocation;
  manager?: Person;
  isRemote: boolean;
  experience: number;
  education: PersonEducation;
  performance: PersonPerformance;
};

export type PersonGender = {
  id: "male" | "female" | "non-binary" | "other";
  name: string;
  order: number;
  icon: LucideIcon;
};

export type PersonDepartment = {
  id: string;
  name: string;
  color: string;
};

export type PersonSkill = {
  id: string;
  name: string;
  level: "beginner" | "intermediate" | "advanced" | "expert";
  color: string;
};

export type PersonLocation = {
  city: string;
  state: string;
  country: string;
  timezone: string;
};

export type PersonEducation = {
  degree: string;
  field: string;
  institution: string;
  graduationYear: number;
};

export type PersonPerformance = {
  rating: number; // 1-5
  lastReview: Date;
  goals: string[];
};

import React, { useEffect, useMemo, useRef, useState } from "react";
import { Button } from "../ui/button.tsx";
import { Separator } from "../ui/separator.tsx";
import { X } from "lucide-react";

import type {
  Column,
  ColumnDataType,
  DataTableFilterActions,
  FilterModel,
  FiltersState,
  FilterStrategy,
} from "../filter-package";
import { getColumn } from "../filter-package";
import { FilterOperator } from "./filter-operator";
import { FilterSubject } from "./filter-subject";
import { FilterValue } from "./filter-value";

interface ActiveFiltersProps<TData> {
  columns: Column<TData>[];
  filters: FiltersState;
  actions: DataTableFilterActions;
  strategy: FilterStrategy;
  entityName?: string;
  aiGenerating?: boolean;
}

export function ActiveFilters<TData>({
  columns,
  filters,
  actions,
  strategy,
  entityName,
  aiGenerating,
}: ActiveFiltersProps<TData>) {
  return (
    <>
      {filters.map((filter) => {
        const id = filter.columnId;

        const column = getColumn(columns, id);

        // Skip if no filter value
        if (!filter.values) return null;

        return (
          <ActiveFilter
            key={`active-filter-${filter.columnId}`}
            filter={filter}
            column={column}
            actions={actions}
            strategy={strategy}
            entityName={entityName}
          />
        );
      })}
      {aiGenerating && <ActiveFilterSkeleton />}
    </>
  );
}

function ActiveFilterSkeleton() {
  return (
    <div className="border-border bg-muted/60 text-muted-foreground flex h-7 items-center gap-2 rounded-2xl border px-3 text-xs shadow-xs">
      <div className="flex items-center gap-2">
        <span className="bg-muted-foreground/60 block h-2 w-10 animate-pulse rounded" />
        <span className="bg-muted-foreground/40 block h-2 w-6 animate-pulse rounded" />
      </div>
    </div>
  );
}

interface ActiveFilterProps<TData, TType extends ColumnDataType> {
  filter: FilterModel<TType>;
  column: Column<TData, TType>;
  actions: DataTableFilterActions;
  strategy: FilterStrategy;
  entityName?: string;
}

// Generic render function for a filter with type-safe value
export function ActiveFilter<TData, TType extends ColumnDataType>({
  filter,
  column,
  actions,
  strategy,
  entityName,
}: ActiveFilterProps<TData, TType>) {
  return (
    <div className="border-border bg-background flex h-7 items-center rounded-2xl border text-xs shadow-xs">
      <FilterSubject column={column} entityName={entityName} />
      <Separator orientation="vertical" />
      <FilterOperator filter={filter} column={column} actions={actions} />
      <Separator orientation="vertical" />
      <FilterValue
        filter={filter}
        column={column}
        actions={actions}
        strategy={strategy}
        entityName={entityName}
      />
      <Separator orientation="vertical" />
      <Button
        variant="ghost"
        className="text-muted-foreground hover:text-primary h-full w-7 rounded-none rounded-r-2xl text-xs"
        onClick={() => actions.removeFilter(filter.columnId)}
      >
        <X className="size-4 -translate-x-0.5" />
      </Button>
    </div>
  );
}

export function ActiveFiltersMobileContainer({
  children,
}: {
  children: React.ReactNode;
}) {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [showLeftBlur, setShowLeftBlur] = useState(false);
  const [showRightBlur, setShowRightBlur] = useState(true);

  // Check if there's content to scroll and update blur states
  const checkScroll = () => {
    if (scrollContainerRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } =
        scrollContainerRef.current;

      // Show left blur if scrolled to the right
      setShowLeftBlur(scrollLeft > 0);

      // Show right blur if there's more content to scroll to the right
      // Add a small buffer (1px) to account for rounding errors
      setShowRightBlur(scrollLeft + clientWidth < scrollWidth - 1);
    }
  };

  // Log blur states for debugging
  // useEffect(() => {
  //   console.log('left:', showLeftBlur, '  right:', showRightBlur)
  // }, [showLeftBlur, showRightBlur])

  // Set up ResizeObserver to monitor container size
  // biome-ignore lint/correctness/useExhaustiveDependencies: <explanation>
  useEffect(() => {
    if (scrollContainerRef.current) {
      const resizeObserver = new ResizeObserver(() => {
        checkScroll();
      });
      resizeObserver.observe(scrollContainerRef.current);
      return () => {
        resizeObserver.disconnect();
      };
    }
  }, []);

  // Update blur states when children change
  // biome-ignore lint/correctness/useExhaustiveDependencies: <explanation>
  useEffect(() => {
    checkScroll();
  }, [children]);

  return (
    <div className="relative w-full overflow-x-hidden">
      {/* Left blur effect */}
      {showLeftBlur && (
        <div className="from-background animate-in fade-in-0 pointer-events-none absolute top-0 bottom-0 left-0 z-10 w-16 bg-gradient-to-r to-transparent" />
      )}

      {/* Scrollable container */}
      <div
        ref={scrollContainerRef}
        className="no-scrollbar flex gap-2 overflow-x-scroll"
        onScroll={checkScroll}
      >
        {children}
      </div>

      {/* Right blur effect */}
      {showRightBlur && (
        <div className="from-background animate-in fade-in-0 pointer-events-none absolute top-0 right-0 bottom-0 z-10 w-16 bg-gradient-to-l to-transparent" />
      )}
    </div>
  );
}

"use client";

import React, { useMemo } from "react";
import { useIsMobile } from "../ui/utils.tsx";

import type {
  Column,
  DataTableFilterActions,
  FiltersState,
  FilterStrategy,
} from "../filter-package";
import { ActiveFilters, ActiveFiltersMobileContainer } from "./active-filters";
import { FilterActions } from "./filter-actions";
import { FilterSelector } from "./filter-selector";
import { useAiFilterSimulation } from "./use-ai-filter-simulation";

interface DataTableFilterProps<TData> {
  columns: Column<TData>[];
  filters: FiltersState;
  actions: DataTableFilterActions;
  strategy: FilterStrategy;
  entityName?: string;
}

export function DataTableFilter<TData>({
  columns,
  filters,
  actions,
  strategy,
  entityName,
}: DataTableFilterProps<TData>) {
  const isMobile = useIsMobile();

  const { aiGenerating, handleAiFilterSubmit } = useAiFilterSimulation({
    columns,
    actions,
  });

  const selectorProps = {
    columns,
    filters,
    actions,
    strategy,
    onAIFilterSubmit: handleAiFilterSubmit,
    aiGenerating,
  } as const;

  if (isMobile) {
    return (
      <div className="flex w-full items-start justify-between gap-2">
        <FilterSelector {...selectorProps} />
        <ActiveFiltersMobileContainer>
          <ActiveFilters
            columns={columns}
            filters={filters}
            actions={actions}
            strategy={strategy}
            entityName={entityName}
            aiGenerating={aiGenerating}
          />
          <FilterActions hasFilters={filters.length > 0} actions={actions} />
        </ActiveFiltersMobileContainer>
      </div>
    );
  }

  return (
    <div className="flex w-full items-start justify-between gap-2">
      <div className="flex w-full flex-1 gap-2 md:flex-wrap">
        <FilterSelector {...selectorProps} />
        <ActiveFilters
          columns={columns}
          filters={filters}
          actions={actions}
          strategy={strategy}
          entityName={entityName}
          aiGenerating={aiGenerating}
        />
        <FilterActions hasFilters={filters.length > 0} actions={actions} />
      </div>
    </div>
  );
}

import React, { memo } from "react";
import { Button } from "../ui/button.tsx";
import { cn } from "../ui/utils.tsx";
import { FilterXIcon } from "lucide-react";

import type { DataTableFilterActions } from "../filter-package";

interface FilterActionsProps {
  hasFilters: boolean;
  actions?: DataTableFilterActions;
}

export const FilterActions = memo(__FilterActions);
function __FilterActions({ hasFilters, actions }: FilterActionsProps) {
  return (
    <Button
      className={cn(
        "text-muted-foreground h-7 px-2 font-normal",
        !hasFilters && "hidden",
      )}
      variant="ghost"
      onClick={actions?.removeAllFilters}
    >
      clear
    </Button>
  );
}

import React, { useState } from "react";
import { Button } from "../ui/button.tsx";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "../ui/command.tsx";
import { Popover, PopoverContent, PopoverTrigger } from "../ui/popover.tsx";

import type {
  Column,
  ColumnDataType,
  DataTableFilterActions,
  FilterModel,
  FilterOperators,
} from "../filter-package";
import {
  booleanFilterOperators,
  dateFilterOperators,
  filterTypeOperatorDetails,
  multiOptionFilterOperators,
  numberFilterOperators,
  optionFilterOperators,
  textFilterOperators,
} from "../filter-package";

interface FilterOperatorProps<TData, TType extends ColumnDataType> {
  column: Column<TData, TType>;
  filter: FilterModel<TType>;
  actions: DataTableFilterActions;
}

// Renders the filter operator display and menu for a given column filter
// The filter operator display is the label and icon for the filter operator
// The filter operator menu is the dropdown menu for the filter operator
export function FilterOperator<TData, TType extends ColumnDataType>({
  column,
  filter,
  actions,
}: FilterOperatorProps<TData, TType>) {
  const [open, setOpen] = useState<boolean>(false);

  const close = () => setOpen(false);

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="ghost"
          className="m-0 h-full w-fit rounded-none p-0 px-2 text-xs whitespace-nowrap"
          onClick={(e) => {
            if (column.type !== "boolean") return;
            e.preventDefault();
            const opDetails =
              filterTypeOperatorDetails.boolean[
                filter.operator as FilterOperators["boolean"]
              ];

            actions.setFilterOperator(
              column.id,
              opDetails.isNegated ? opDetails.negationOf : opDetails.negation,
            );
          }}
        >
          <FilterOperatorDisplay filter={filter} columnType={column.type} />
        </Button>
      </PopoverTrigger>
      <PopoverContent
        align="start"
        className="w-fit origin-(--radix-popover-content-transform-origin) p-0"
      >
        <Command loop>
          <CommandInput placeholder="search" />
          <CommandEmpty>No results</CommandEmpty>
          <CommandList className="max-h-fit">
            <FilterOperatorController
              filter={filter}
              column={column}
              actions={actions}
              closeController={close}
            />
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  );
}

interface FilterOperatorDisplayProps<TType extends ColumnDataType> {
  filter: FilterModel<TType>;
  columnType: TType;
}

export function FilterOperatorDisplay<TType extends ColumnDataType>({
  filter,
  columnType,
}: FilterOperatorDisplayProps<TType>) {
  const operator = filterTypeOperatorDetails[columnType][filter.operator];
  const label = operator.key;

  return <span className="text-muted-foreground">{label}</span>;
}

interface FilterOperatorControllerProps<TData, TType extends ColumnDataType> {
  filter: FilterModel<TType>;
  column: Column<TData, TType>;
  actions: DataTableFilterActions;
  closeController: () => void;
}

/*
 *
 * TODO: Reduce into a single component. Each data type does not need it's own controller.
 *
 */
export function FilterOperatorController<TData, TType extends ColumnDataType>({
  filter,
  column,
  actions,
  closeController,
}: FilterOperatorControllerProps<TData, TType>) {
  switch (column.type) {
    case "option":
      return (
        <FilterOperatorOptionController
          filter={filter as FilterModel<"option">}
          column={column as Column<TData, "option">}
          actions={actions}
          closeController={closeController}
        />
      );
    case "multiOption":
      return (
        <FilterOperatorMultiOptionController
          filter={filter as FilterModel<"multiOption">}
          column={column as Column<TData, "multiOption">}
          actions={actions}
          closeController={closeController}
        />
      );
    case "date":
      return (
        <FilterOperatorDateController
          filter={filter as FilterModel<"date">}
          column={column as Column<TData, "date">}
          actions={actions}
          closeController={closeController}
        />
      );
    case "text":
      return (
        <FilterOperatorTextController
          filter={filter as FilterModel<"text">}
          column={column as Column<TData, "text">}
          actions={actions}
          closeController={closeController}
        />
      );
    case "number":
      return (
        <FilterOperatorNumberController
          filter={filter as FilterModel<"number">}
          column={column as Column<TData, "number">}
          actions={actions}
          closeController={closeController}
        />
      );
    case "boolean":
      return (
        <FilterOperatorBooleanController
          filter={filter as FilterModel<"boolean">}
          column={column as Column<TData, "boolean">}
          actions={actions}
          closeController={closeController}
        />
      );
    default:
      return null;
  }
}

function FilterOperatorOptionController<TData>({
  filter,
  column,
  actions,
  closeController,
}: FilterOperatorControllerProps<TData, "option">) {
  const filterDetails = optionFilterOperators[filter.operator];

  const relatedFilters = Object.values(optionFilterOperators).filter(
    (o) => o.target === filterDetails.target,
  );

  const changeOperator = (value: string) => {
    actions?.setFilterOperator(column.id, value as FilterOperators["option"]);
    closeController();
  };

  return (
    <CommandGroup heading="operators">
      {relatedFilters.map((r) => {
        return (
          <CommandItem onSelect={changeOperator} value={r.value} key={r.value}>
            {r.key}
          </CommandItem>
        );
      })}
    </CommandGroup>
  );
}

function FilterOperatorMultiOptionController<TData>({
  filter,
  column,
  actions,
  closeController,
}: FilterOperatorControllerProps<TData, "multiOption">) {
  const filterDetails = multiOptionFilterOperators[filter.operator];

  const relatedFilters = Object.values(multiOptionFilterOperators).filter(
    (o) => o.target === filterDetails.target,
  );

  const changeOperator = (value: string) => {
    actions?.setFilterOperator(
      column.id,
      value as FilterOperators["multiOption"],
    );
    closeController();
  };

  return (
    <CommandGroup heading="operators">
      {relatedFilters.map((r) => {
        return (
          <CommandItem onSelect={changeOperator} value={r.value} key={r.value}>
            {r.key}
          </CommandItem>
        );
      })}
    </CommandGroup>
  );
}

function FilterOperatorDateController<TData>({
  filter,
  column,
  actions,
  closeController,
}: FilterOperatorControllerProps<TData, "date">) {
  const filterDetails = dateFilterOperators[filter.operator];

  const relatedFilters = Object.values(dateFilterOperators).filter(
    (o) => o.target === filterDetails.target,
  );

  const changeOperator = (value: string) => {
    actions?.setFilterOperator(column.id, value as FilterOperators["date"]);
    closeController();
  };

  return (
    <CommandGroup>
      {relatedFilters.map((r) => {
        return (
          <CommandItem onSelect={changeOperator} value={r.value} key={r.value}>
            {r.key}
          </CommandItem>
        );
      })}
    </CommandGroup>
  );
}

export function FilterOperatorTextController<TData>({
  filter,
  column,
  actions,
  closeController,
}: FilterOperatorControllerProps<TData, "text">) {
  const filterDetails = textFilterOperators[filter.operator];

  const relatedFilters = Object.values(textFilterOperators).filter(
    (o) => o.target === filterDetails.target,
  );

  const changeOperator = (value: string) => {
    actions?.setFilterOperator(column.id, value as FilterOperators["text"]);
    closeController();
  };

  return (
    <CommandGroup heading="operators">
      {relatedFilters.map((r) => {
        return (
          <CommandItem onSelect={changeOperator} value={r.value} key={r.value}>
            {r.key}
          </CommandItem>
        );
      })}
    </CommandGroup>
  );
}

function FilterOperatorNumberController<TData>({
  filter,
  column,
  actions,
  closeController,
}: FilterOperatorControllerProps<TData, "number">) {
  const filterDetails = numberFilterOperators[filter.operator];

  const relatedFilters = Object.values(numberFilterOperators).filter(
    (o) => o.target === filterDetails.target,
  );

  const changeOperator = (value: string) => {
    actions?.setFilterOperator(column.id, value as FilterOperators["number"]);
    closeController();
  };

  return (
    <div>
      <CommandGroup heading="operators">
        {relatedFilters.map((r) => (
          <CommandItem
            onSelect={() => changeOperator(r.value)}
            value={r.value}
            key={r.value}
          >
            {r.key}
          </CommandItem>
        ))}
      </CommandGroup>
    </div>
  );
}

function FilterOperatorBooleanController<TData>({
  filter,
  column,
  actions,
  closeController,
}: FilterOperatorControllerProps<TData, "boolean">) {
  const filterDetails = booleanFilterOperators[filter.operator];

  const relatedFilters = Object.values(booleanFilterOperators).filter(
    (o) => o.target === filterDetails.target,
  );

  const changeOperator = (value: string) => {
    actions?.setFilterOperator(column.id, value as FilterOperators["boolean"]);
    closeController();
  };

  return (
    <div>
      <CommandGroup heading="operators">
        {relatedFilters.map((r) => (
          <CommandItem
            onSelect={() => changeOperator(r.value)}
            value={r.value}
            key={r.value}
          >
            {r.key}
          </CommandItem>
        ))}
      </CommandGroup>
    </div>
  );
}

import React, {
  isValidElement,
  memo,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { Button } from "../ui/button.tsx";
import { Checkbox } from "../ui/checkbox.tsx";
import {
  Command,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "../ui/command.tsx";
import { Popover, PopoverContent, PopoverTrigger } from "../ui/popover.tsx";
import {
  ArrowLeftIcon,
  ArrowRightIcon,
  ChevronRightIcon,
  ListFilterIcon,
  SparklesIcon,
} from "lucide-react";

import type {
  Column,
  ColumnDataType,
  DataTableFilterActions,
  FiltersState,
  FilterStrategy,
} from "../filter-package";
import { getColumn, isAnyOf } from "../filter-package";
import { FilterValueController } from "./filter-value";

interface FilterSelectorProps<TData> {
  filters: FiltersState;
  columns: Column<TData>[];
  actions: DataTableFilterActions;
  strategy: FilterStrategy;
  onAIFilterSubmit?: (prompt: string) => void;
  aiGenerating?: boolean;
}

export const FilterSelector = memo(__FilterSelector) as typeof __FilterSelector;

function __FilterSelector<TData>({
  filters,
  columns,
  actions,
  strategy,
  onAIFilterSubmit,
  aiGenerating,
}: FilterSelectorProps<TData>) {
  const [open, setOpen] = useState(false);
  const [value, setValue] = useState("");
  const [property, setProperty] = useState<string | undefined>(undefined);
  const inputRef = useRef<HTMLInputElement>(null);

  const visibleColumns = useMemo(
    () => columns.filter((c) => !c.hidden),
    [columns],
  );

  const visibleFilters = useMemo(
    () =>
      filters.filter((f) => visibleColumns.find((c) => c.id === f.columnId)),
    [filters, visibleColumns],
  );

  const column = property ? getColumn(visibleColumns, property) : undefined;
  const filter = property
    ? visibleFilters.find((f) => f.columnId === property)
    : undefined;

  useEffect(() => {
    if (property && inputRef) {
      inputRef.current?.focus();
      setValue("");
    }
  }, [property]);

  useEffect(() => {
    if (!open) setTimeout(() => setValue(""), 150);
  }, [open]);

  const content = useMemo(
    () =>
      property && column && column.type !== "boolean" ? (
        <div className="flex flex-col">
          <div className="flex h-9 items-center gap-2 border-b px-2">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setProperty(undefined)}
              className="h-6 w-6 p-0"
            >
              <ArrowLeftIcon className="size-4" />
              <span className="sr-only">Back</span>
            </Button>
            <div className="flex items-center gap-1.5 text-sm">
              {column.icon &&
                (isValidElement(column.icon) ? (
                  column.icon
                ) : (
                  <column.icon className="size-4 stroke-[2.25px]" />
                ))}
              <span className="font-medium">{column.displayName}</span>
            </div>
          </div>
          <FilterValueController
            filter={filter!}
            column={column as Column<TData, ColumnDataType>}
            actions={actions}
            strategy={strategy}
          />
        </div>
      ) : (
        <Command
          loop
          filter={(value, search, keywords) => {
            const extendValue = `${value} ${keywords?.join(" ")}`;
            return extendValue.toLowerCase().includes(search.toLowerCase())
              ? 1
              : 0;
          }}
        >
          <CommandInput
            value={value}
            onValueChange={setValue}
            ref={inputRef}
            placeholder="Search or ask AI"
          />
          <CommandList className="max-h-fit">
            <CommandGroup>
              <CommandItem
                value={value}
                disabled={!onAIFilterSubmit || aiGenerating}
                onSelect={() => {
                  const prompt = value.trim();
                  if (!prompt || !onAIFilterSubmit) return;

                  onAIFilterSubmit(prompt);
                  setOpen(false);
                  setTimeout(() => {
                    setValue("");
                    setProperty(undefined);
                  }, 100);
                }}
              >
                <div className="flex w-full items-center justify-between gap-2">
                  <div className="flex items-center gap-2">
                    <SparklesIcon className="size-4" />
                    <span>Ask AI</span>
                  </div>
                  <span className="text-muted-foreground truncate text-xs">
                    {value.trim().length > 0
                      ? `"${value.trim()}"`
                      : "Type a prompt"}
                  </span>
                </div>
              </CommandItem>
              {visibleColumns.map((column) => (
                <FilterableColumn
                  key={column.id}
                  column={column}
                  setProperty={setProperty}
                  actions={actions}
                  filters={visibleFilters}
                />
              ))}
              <QuickSearchFilters
                search={value}
                filters={visibleFilters}
                columns={visibleColumns}
                actions={actions}
                strategy={strategy}
              />
            </CommandGroup>
          </CommandList>
        </Command>
      ),
    [
      aiGenerating,
      property,
      column,
      filter,
      visibleFilters,
      visibleColumns,
      actions,
      value,
      strategy,
      onAIFilterSubmit,
    ],
  );

  return (
    <Popover
      open={open}
      onOpenChange={async (value) => {
        setOpen(value);
        if (!value) {
          setTimeout(() => setProperty(undefined), 100);
        }
      }}
    >
      <PopoverTrigger asChild>
        <Button variant="ghost" size="icon" className="size-7 p-0">
          <ListFilterIcon className="size-4" />
        </Button>
      </PopoverTrigger>
      <PopoverContent
        align="start"
        side="bottom"
        className="w-fit origin-(--radix-popover-content-transform-origin) p-0"
      >
        {content}
      </PopoverContent>
    </Popover>
  );
}

export function FilterableColumn<TData, TType extends ColumnDataType, TVal>({
  column,
  setProperty,
  actions,
  filters,
}: {
  column: Column<TData, TType, TVal>;
  setProperty: (value: string) => void;
  actions: DataTableFilterActions;
  filters: FiltersState;
}) {
  const itemRef = useRef<HTMLDivElement>(null);

  const { icon: Icon } = column;
  const hasIcon = !!Icon;

  // Check if this column is being filtered
  const isFiltered = filters.some(
    (filter) => filter.columnId === column.id && filter.values.length > 0,
  );

  const prefetch = useCallback(() => {
    column.prefetchValues();

    // Only prefetch options and faceted values for option and multi-option columns
    if (isAnyOf(column.type, ["option", "multiOption"])) {
      column.prefetchOptions();
      column.prefetchFacetedUniqueValues();
    }

    // Only prefetch min/max values for number columns
    if (column.type === "number") {
      column.prefetchFacetedMinMaxValues();
    }
  }, [column]);

  useEffect(() => {
    const target = itemRef.current;

    if (!target) return;

    // Set up MutationObserver
    const observer = new MutationObserver((mutations) => {
      for (const mutation of mutations) {
        if (mutation.type === "attributes") {
          const isSelected = target.getAttribute("data-selected") === "true";
          if (isSelected) prefetch();
        }
      }
    });

    // Set up observer
    observer.observe(target, {
      attributes: true,
      attributeFilter: ["data-selected"],
    });

    // Cleanup on unmount
    return () => observer.disconnect();
  }, [prefetch]);

  function handleSelect() {
    if (column.type === "boolean") {
      actions.setFilterValue(column as any, [true]);
      return;
    }

    setProperty(column.id);
  }

  return (
    <CommandItem
      ref={itemRef}
      value={column.id}
      keywords={[column.displayName]}
      onSelect={handleSelect}
      className="group"
      onMouseEnter={prefetch}
    >
      <div className="flex w-full items-center justify-between">
        <div className="inline-flex items-center gap-1.5">
          {hasIcon && (
            <div className="relative">
              {isValidElement(Icon) ? (
                Icon
              ) : (
                <Icon className="size-4 stroke-[2.25px]" />
              )}
              {isFiltered && (
                <div className="absolute -right-0.5 -bottom-0.5 h-2 w-2 rounded-full bg-green-500" />
              )}
            </div>
          )}
          {!hasIcon && isFiltered && (
            <div className="h-2 w-2 rounded-full bg-green-500" />
          )}
          <span>{column.displayName}</span>
        </div>
        {column.type !== "boolean" && (
          <ArrowRightIcon className="size-4 opacity-0 group-aria-selected:opacity-100" />
        )}
      </div>
    </CommandItem>
  );
}

interface QuickSearchFiltersProps<TData> {
  search?: string;
  filters: FiltersState;
  columns: Column<TData>[];
  actions: DataTableFilterActions;
  strategy: FilterStrategy;
}

export const QuickSearchFilters = memo(
  __QuickSearchFilters,
) as typeof __QuickSearchFilters;

function __QuickSearchFilters<TData>({
  search,
  filters,
  columns,
  actions,
  strategy,
}: QuickSearchFiltersProps<TData>) {
  if (!search || search.trim().length < 2) return null;

  // biome-ignore lint/correctness/useHookAtTopLevel: its okay
  const cols = useMemo(
    () =>
      columns.filter((c) =>
        isAnyOf<ColumnDataType>(c.type, ["option", "multiOption"]),
      ),
    [columns],
  );

  return (
    <>
      {cols.map((column) => {
        const filter = filters.find((f) => f.columnId === column.id);
        const options = column.getOptions();

        function handleOptionSelect(value: string, check: boolean) {
          if (check) actions.addFilterValue(column, [value]);
          else actions.removeFilterValue(column, [value]);
        }

        return (
          <React.Fragment key={column.id}>
            {options.map((v) => {
              const checked = Boolean(filter?.values.includes(v.value));

              return (
                <CommandItem
                  key={v.value}
                  value={v.value}
                  keywords={[v.label, v.value]}
                  onSelect={() => {
                    handleOptionSelect(v.value, !checked);
                  }}
                  className="group"
                >
                  <div className="group flex items-center gap-1.5">
                    <Checkbox
                      checked={checked}
                      className="dark:border-ring mr-1 opacity-0 group-data-[selected=true]:opacity-100 data-[state=checked]:opacity-100"
                    />
                    <div className="flex w-4 items-center justify-center">
                      {v.icon &&
                        (isValidElement(v.icon) ? (
                          v.icon
                        ) : (
                          <v.icon className="text-primary size-4" />
                        ))}
                    </div>
                    <div className="flex items-center gap-0.5">
                      <span className="text-muted-foreground">
                        {column.displayName}
                      </span>
                      <ChevronRightIcon className="text-muted-foreground/75 size-3.5" />
                      <span>{v.label}</span>
                    </div>
                  </div>
                </CommandItem>
              );
            })}
          </React.Fragment>
        );
      })}
    </>
  );
}

