/*
 *
 * Determines the new operator for a filter based on the current operator, old and new filter values.
 *
 * This handles cases where the filter values have transitioned from a single value to multiple values (or vice versa),
 * and the current operator needs to be transitioned to its plural form (or singular form).
 *
 * For example, if the current operator is 'is', and the new filter values have a length of 2, the
 * new operator would be 'is any of'.
 *
 */
export function determineNewOperator<TType extends ColumnDataType>(
  type: TType,
  oldVals: FilterValues<TType>,
  nextVals: FilterValues<TType>,
  currentOperator: FilterOperators[TType],
): FilterOperators[TType] {
  const a =
    Array.isArray(oldVals) && Array.isArray(oldVals[0])
      ? oldVals[0].length
      : oldVals.length;
  const b =
    Array.isArray(nextVals) && Array.isArray(nextVals[0])
      ? nextVals[0].length
      : nextVals.length;

  // If filter size has not transitioned from single to multiple (or vice versa)
  // or is unchanged, return the current operator.
  if (a === b || (a >= 2 && b >= 2) || (a <= 1 && b <= 1))
    return currentOperator;

  const opDetails = filterTypeOperatorDetails[type][currentOperator];

  // Handle transition from single to multiple filter values.
  if (a < b && b >= 2) return opDetails.singularOf ?? currentOperator;
  // Handle transition from multiple to single filter values.
  if (a > b && b <= 1) return opDetails.pluralOf ?? currentOperator;
  return currentOperator;
}

import type { orderFns } from "../lib/order-fns";

/*
 * # GENERAL NOTES:
 *
 * ## GENERICS:
 *
 * TData is the shape of a single row in your data table.
 * TVal is the shape of the underlying value for a column.
 * TType is the type (kind) of the column.
 *
 */

export type ElementType<T> = T extends (infer U)[] ? U : T;

export type Nullable<T> = T | null | undefined;

export type FiltersStateUpdaterFn<TContext> = (
  prev: FiltersState,
  next: FiltersState,
  context?: TContext,
) => void;

/**
 * Interface for column metadata that can be extended via declaration merging.
 * Users can augment this interface to add custom metadata properties.
 *
 * @example
 * ```typescript
 * declare module '@bazzaui/filters' {
 *   interface ColumnMeta {
 *     tooltip?: string
 *     category?: string
 *     sortable?: boolean
 *   }
 * }
 * ```
 */
// biome-ignore lint/suspicious/noEmptyInterface: consumers can override this
export interface ColumnMeta {}

/*
 * The model of a column option.
 * Used for representing underlying column values of type `option` or `multiOption`.
 */
export interface ColumnOption {
  /* The label to display for the option. */
  label: string;
  /* The internal value of the option. */
  value: string;
  /* An optional icon to display next to the label. */
  icon?: React.ReactElement | React.ElementType;
  /* The count of this option in the data (automatically populated from faceted data). */
  count?: number;
}

export interface ColumnOptionExtended extends ColumnOption {
  selected?: boolean;
  count?: number;
}

export type NumericValue = number | bigint;

/*
 * Represents the data type (kind) of a column.
 */
export type ColumnDataType =
  /* The column value is a string that should be searchable. */
  | "text"
  | "number"
  | "bigint"
  | "date"
  | "boolean"
  /* The column value can be a single value from a list of options. */
  | "option"
  /* The column value can be zero or more values from a list of options. */
  | "multiOption";

/*
 * Represents the data type (kind) of option and multi-option columns.
 */
export type OptionBasedColumnDataType = Extract<
  ColumnDataType,
  "option" | "multiOption"
>;

/*
 * Maps a ColumnDataType to it's primitive type (i.e. string, number, etc.).
 */
export type ColumnDataNativeMap = {
  text: string;
  number: number;
  bigint: bigint;
  date: Date;
  boolean: boolean;
  option: string;
  multiOption: string[];
};

/*
 * Represents the value of a column filter.
 * Contigent on the filtered column's data type.
 */
export type FilterValues<T extends ColumnDataType> = Array<
  ElementType<ColumnDataNativeMap[T]>
>;

/*
 * An accessor function for a column's data.
 * Uses the original row data as an argument.
 */
export type TAccessorFn<TData, TVal = unknown> = (data: TData) => TVal;

/*
 * Used by `option` and `multiOption` columns.
 * Transforms the underlying column value into a valid ColumnOption.
 */
export type TTransformValueToOptionFn<TVal = unknown> = (
  value: ElementType<NonNullable<TVal>>,
) => ColumnOption;

export type TOrderFns = Array<TOrderFn>;

export type TOrderFn = TCustomOrderFn;

export type TCustomOrderFn = (a: ColumnOption, b: ColumnOption) => number;

export type TBuiltInOrderFn = (
  a: ColumnOption,
  b: ColumnOption,
  direction: OrderDirection,
) => number;

export type TOrderFnArg =
  | [TBuiltInOrderFnName, OrderDirection]
  | TCustomOrderFn;

/*
 * Used by `option` and `multiOption` columns.
 * The direction of ordering for built-in ordering functions.
 */
export type OrderDirection = "asc" | "desc";

export type TBuiltInOrderFnName = keyof typeof orderFns;

/*
 * Used by `option` and `multiOption` columns.
 * Transforms the computed column options after initial computation, with access to faceted data.
 * Applied AFTER transformValueToOptionFn.
 */
export type TTransformOptionsFn = (options: ColumnOption[]) => ColumnOption[];

/*
 * The configuration for a column.
 */
export type ColumnConfig<
  TData,
  TType extends ColumnDataType = any,
  TVal = unknown,
  TId extends string = string,
> = {
  id: TId;
  accessor: TAccessorFn<TData, TVal>;
  displayName: string;
  icon?: React.ReactElement | React.ElementType;
  type: TType;
  hidden?: boolean;
  options?: TType extends OptionBasedColumnDataType ? ColumnOption[] : never;
  facetedOptions?: TType extends OptionBasedColumnDataType
    ? Map<string, number>
    : never;
  min?: TType extends "number"
    ? number
    : TType extends "bigint"
      ? bigint
      : never;
  max?: TType extends "number"
    ? number
    : TType extends "bigint"
      ? bigint
      : never;
  transformValueToOptionFn?: TType extends OptionBasedColumnDataType
    ? TTransformValueToOptionFn<TVal>
    : never;
  orderFn?: TType extends OptionBasedColumnDataType ? TOrderFns : never;
  transformOptionsFn?: TType extends OptionBasedColumnDataType
    ? TTransformOptionsFn
    : never;
  toggledStateName?: TType extends "boolean" ? string : never;
  meta?: ColumnMeta;
};

export type OptionColumnId<T> =
  T extends ColumnConfig<
    infer TData,
    "option" | "multiOption",
    infer TVal,
    infer TId
  >
    ? TId
    : never;

export type OptionColumnIds<
  T extends ReadonlyArray<ColumnConfig<any, any, any, any>>,
> = {
  [K in keyof T]: OptionColumnId<T[K]>;
}[number];

export type NumberColumnId<T> =
  T extends ColumnConfig<infer TData, "number", infer TVal, infer TId>
    ? TId
    : never;

export type NumberColumnIds<
  T extends ReadonlyArray<ColumnConfig<any, any, any, any>>,
> = {
  [K in keyof T]: NumberColumnId<T[K]>;
}[number];

/*
 * Describes a helper function for creating column configurations.
 */
export type ColumnConfigHelper<TData> = {
  accessor: <
    TAccessor extends TAccessorFn<TData>,
    TType extends ColumnDataType,
    TVal extends ReturnType<TAccessor>,
  >(
    accessor: TAccessor,
    config?: Omit<ColumnConfig<TData, TType, TVal>, "accessor">,
  ) => ColumnConfig<TData, TType, unknown>;
};

export type DataTableFilterConfig<TData> = {
  data: TData[];
  columns: ColumnConfig<TData>[];
};

export type MinMaxReturn<T extends ColumnDataType> = T extends "number"
  ? [number, number] | undefined
  : T extends "bigint"
    ? [bigint, bigint] | undefined
    : undefined;

export type ColumnProperties<TData, TType extends ColumnDataType, TVal> = {
  getOptions: () => ColumnOption[];
  getValues: () => ElementType<NonNullable<TVal>>[];
  getFacetedUniqueValues: () => Map<string, number> | undefined;
  getFacetedMinMaxValues: () => MinMaxReturn<TType>;
  prefetchOptions: () => Promise<void>; // Prefetch options
  prefetchValues: () => Promise<void>; // Prefetch values
  prefetchFacetedUniqueValues: () => Promise<void>; // Prefetch faceted unique values
  prefetchFacetedMinMaxValues: () => Promise<void>; // Prefetch faceted min/max values
};

export type ColumnPrivateProperties<TData, TVal> = {
  _prefetchedOptionsCache: ColumnOption[] | null;
  _prefetchedValuesCache: ElementType<NonNullable<TVal>>[] | null;
  _prefetchedFacetedUniqueValuesCache: Map<string, number> | null;
  _prefetchedFacetedMinMaxValuesCache: [number, number] | null;
};

export type Column<
  TData,
  TType extends ColumnDataType = any,
  TVal = unknown,
> = ColumnConfig<TData, TType, TVal> &
  ColumnProperties<TData, TType, TVal> &
  ColumnPrivateProperties<TData, TVal>;

export interface DataTableFilterActions<TContext = any> {
  addFilterValue: <TData, TType extends OptionBasedColumnDataType>(
    column: Column<TData, TType>,
    values: FilterModel<TType>["values"],
    context?: TContext,
  ) => void;

  removeFilterValue: <TData, TType extends OptionBasedColumnDataType>(
    column: Column<TData, TType>,
    value: FilterModel<TType>["values"],
    context?: TContext,
  ) => void;

  setFilterValue: <TData, TType extends ColumnDataType>(
    column: Column<TData, TType>,
    values: FilterModel<TType>["values"],
    context?: TContext,
  ) => void;

  setFilterOperator: <TType extends ColumnDataType>(
    columnId: string,
    operator: FilterModel<TType>["operator"],
    context?: TContext,
  ) => void;

  removeFilter: (columnId: string, context?: TContext) => void;

  removeAllFilters: (context?: TContext) => void;

  batch: (
    callback: (batchActions: DataTableFilterBatchActions) => void,
    context?: TContext,
  ) => void;
}

export interface FilterOperations {
  addFilterValue: <TData, TType extends OptionBasedColumnDataType>(
    filters: FiltersState,
    column: Column<TData, TType>,
    values: FilterModel<TType>["values"],
  ) => FiltersState;

  removeFilterValue: <TData, TType extends OptionBasedColumnDataType>(
    filters: FiltersState,
    column: Column<TData, TType>,
    value: FilterModel<TType>["values"],
  ) => FiltersState;

  setFilterValue: <TData, TType extends ColumnDataType>(
    filters: FiltersState,
    column: Column<TData, TType>,
    values: FilterModel<TType>["values"],
  ) => FiltersState;

  setFilterOperator: <TType extends ColumnDataType>(
    filters: FiltersState,
    columnId: string,
    operator: FilterModel<TType>["operator"],
  ) => FiltersState;

  removeFilter: (filters: FiltersState, columnId: string) => FiltersState;

  removeAllFilters: (filters: FiltersState) => FiltersState;
}

export interface DataTableFilterBatchActions extends BatchFilterOperations {}

export interface BatchFilterOperations {
  addFilterValue: <TData, TType extends OptionBasedColumnDataType>(
    column: Column<TData, TType>,
    values: FilterModel<TType>["values"],
  ) => void;

  removeFilterValue: <TData, TType extends OptionBasedColumnDataType>(
    column: Column<TData, TType>,
    value: FilterModel<TType>["values"],
  ) => void;

  setFilterValue: <TData, TType extends ColumnDataType>(
    column: Column<TData, TType>,
    values: FilterModel<TType>["values"],
  ) => void;

  setFilterOperator: <TType extends ColumnDataType>(
    columnId: string,
    operator: FilterModel<TType>["operator"],
  ) => void;

  removeFilter: (columnId: string) => void;

  removeAllFilters: () => void;
}

export type FilterStrategy = "client" | "server";

/* Operators for text data */
export type TextFilterOperator = "contains" | "does not contain";

/* Operators for number data */
export type NumberFilterOperator =
  | "is"
  | "is not"
  | "is less than"
  | "is greater than or equal to"
  | "is greater than"
  | "is less than or equal to"
  | "is between"
  | "is not between";

export type BigIntFilterOperator = NumberFilterOperator;

/* Operators for date data */
export type DateFilterOperator =
  | "is"
  | "is not"
  | "is before"
  | "is on or after"
  | "is after"
  | "is on or before"
  | "is between"
  | "is not between";

/* Operators for boolean data */
export type BooleanFilterOperator = "is" | "is not";

/* Operators for option data */
export type OptionFilterOperator = "is" | "is not" | "is any of" | "is none of";

/* Operators for multi-option data */
export type MultiOptionFilterOperator =
  | "include"
  | "exclude"
  | "include any of"
  | "include all of"
  | "exclude if any of"
  | "exclude if all";

/* Maps filter operators to their respective data types */
export type FilterOperators = {
  text: TextFilterOperator;
  number: NumberFilterOperator;
  bigint: BigIntFilterOperator;
  date: DateFilterOperator;
  boolean: BooleanFilterOperator;
  option: OptionFilterOperator;
  multiOption: MultiOptionFilterOperator;
};

/*
 *
 * FilterValue is a type that represents a filter value for a specific column.
 *
 * It consists of:
 * - Operator: The operator to be used for the filter.
 * - Values: An array of values to be used for the filter.
 *
 */
export type FilterModel<TType extends ColumnDataType = any> = {
  columnId: string;
  type: TType;
  operator: FilterOperators[TType];
  values: FilterValues<TType>;
};

export type FiltersState = Array<FilterModel>;

/*
 * FilterDetails is a type that represents the details of all the filter operators for a specific column data type.
 */
export type FilterDetails<T extends ColumnDataType> = {
  [key in FilterOperators[T]]: FilterOperatorDetails<key, T>;
};

export type FilterOperatorTarget = "single" | "multiple";

export type FilterOperatorDetailsBase<
  OperatorValue,
  T extends ColumnDataType,
> = {
  /* The display text for the operator. */
  key: string;
  /* The operator value. Usually the string representation of the operator. */
  value: OperatorValue;
  /* How much data the operator applies to. */
  target: FilterOperatorTarget;
  /* The plural form of the operator, if applicable. */
  singularOf?: FilterOperators[T];
  /* The singular form of the operator, if applicable. */
  pluralOf?: FilterOperators[T];
  /* All related operators. Normally, all the operators which share the same target. */
  relativeOf: FilterOperators[T] | Array<FilterOperators[T]>;
  /* Whether the operator is negated. */
  isNegated: boolean;
  /* If the operator is not negated, this provides the negated equivalent. */
  negation?: FilterOperators[T];
  /* If the operator is negated, this provides the positive equivalent. */
  negationOf?: FilterOperators[T];
};

/*
 *
 * FilterOperatorDetails is a type that provides details about a filter operator for a specific column data type.
 * It extends FilterOperatorDetailsBase with additional logic and contraints on the defined properties.
 *
 */
export type FilterOperatorDetails<
  OperatorValue,
  T extends ColumnDataType,
> = FilterOperatorDetailsBase<OperatorValue, T> &
  (
    | { singularOf?: never; pluralOf?: never }
    | { target: "single"; singularOf: FilterOperators[T]; pluralOf?: never }
    | { target: "multiple"; singularOf?: never; pluralOf: FilterOperators[T] }
  ) &
  (
    | { isNegated: false; negation: FilterOperators[T]; negationOf?: never }
    | { isNegated: true; negation?: never; negationOf: FilterOperators[T] }
  );

/* Maps column data types to their respective filter operator details */
export type FilterTypeOperatorDetails = {
  [key in ColumnDataType]: FilterDetails<key>;
};

export interface DataTableFiltersOptions<
  TData,
  TColumns extends ReadonlyArray<ColumnConfig<TData, any, any, any>>,
  TStrategy extends FilterStrategy,
  TContext = any,
> {
  strategy: TStrategy;
  data: TData[];
  columnsConfig: TColumns;
  defaultFilters?: FiltersState;
  filters?: FiltersState;
  onFiltersChange?:
    | React.Dispatch<React.SetStateAction<FiltersState>>
    | FiltersStateUpdaterFn<TContext>;
  options?: Partial<
    Record<OptionColumnIds<TColumns>, ColumnOption[] | undefined>
  >;
  faceted?: Partial<
    | Record<OptionColumnIds<TColumns>, Map<string, number> | undefined>
    | Record<NumberColumnIds<TColumns>, [number, number] | undefined>
  >;
  entityName?: string;
}

export interface DataTableFiltersInstance<
  TData,
  TStrategy extends FilterStrategy,
  TContext,
> {
  columns: Column<TData>[];
  filters: FiltersState;
  actions: DataTableFilterActions<TContext>;
  strategy: TStrategy;
  entityName?: string;
}

"use client";

import type React from "react";
import { useCallback, useMemo, useState } from "react";

import type {
  BatchFilterOperations,
  Column,
  ColumnConfig,
  ColumnDataType,
  DataTableFilterActions,
  DataTableFilterBatchActions,
  DataTableFiltersInstance,
  DataTableFiltersOptions,
  FilterModel,
  FiltersState,
  FilterStrategy,
  NumberColumnIds,
  OptionBasedColumnDataType,
  OptionColumnIds,
} from "../core/types";
import { createColumns } from "../core/columns/index";
import { filterOperations } from "../core/filters";
import {
  isColumnOptionArray,
  isColumnOptionMap,
  isMinMaxTuple,
} from "../lib/helpers";

export function useDataTableFilters<
  TData,
  TColumns extends ReadonlyArray<ColumnConfig<TData, any, any, any>>,
  TStrategy extends FilterStrategy,
  TContext,
>({
  strategy,
  data,
  columnsConfig,
  defaultFilters,
  filters: externalFilters,
  onFiltersChange,
  options,
  faceted,
  entityName,
}: DataTableFiltersOptions<
  TData,
  TColumns,
  TStrategy,
  TContext
>): DataTableFiltersInstance<TData, TStrategy, TContext> {
  const [internalFilters, setInternalFilters] = useState<FiltersState>(
    defaultFilters ?? [],
  );

  if (
    (externalFilters && !onFiltersChange) ||
    (!externalFilters && onFiltersChange)
  ) {
    throw new Error(
      "If using controlled state, you must specify both filters and onFiltersChange.",
    );
  }

  const isControlled =
    externalFilters !== undefined && onFiltersChange !== undefined;

  const filters = isControlled ? externalFilters : internalFilters;

  const setFilters = useCallback(
    (
      nextFilters: FiltersState | ((prev: FiltersState) => FiltersState),
      context?: TContext,
    ) => {
      // Handle change for controlled mode
      if (isControlled) {
        // For controlled mode, we need to resolve the function and call the handler
        const prevFilters = filters;
        const resolvedNextFilters =
          typeof nextFilters === "function"
            ? nextFilters(prevFilters) // If function: call it with prev to get next
            : nextFilters; // If value: use it directly

        // Detect handler type by function length and call appropriately
        if (onFiltersChange.length <= 1) {
          // React Dispatch style
          const dispatchHandler = onFiltersChange as React.Dispatch<
            React.SetStateAction<FiltersState>
          >;
          dispatchHandler(resolvedNextFilters);
        } else {
          // Custom handler style - pass prev, next, and context
          const customHandler = onFiltersChange as (
            prev: FiltersState,
            next: FiltersState,
            context?: TContext,
          ) => void;

          customHandler(prevFilters, resolvedNextFilters, context);
        }
      } else if (!isControlled) {
        // Uncontrolled mode: let React handle the function resolution
        setInternalFilters(nextFilters);
      }
    },
    [filters, isControlled, onFiltersChange],
  );

  // Convert ColumnConfig to Column, applying options and faceted options if provided
  const columns = useMemo(() => {
    const enhancedConfigs = columnsConfig.map((config) => {
      let final = config;

      // Set options, if exists
      if (
        options &&
        (config.type === "option" || config.type === "multiOption")
      ) {
        const optionsInput = options[config.id as OptionColumnIds<TColumns>];
        if (!optionsInput || !isColumnOptionArray(optionsInput)) return config;

        final = { ...final, options: optionsInput };
      }

      // Set faceted options, if exists
      if (
        faceted &&
        (config.type === "option" || config.type === "multiOption")
      ) {
        const facetedOptionsInput =
          faceted[config.id as OptionColumnIds<TColumns>];
        if (!facetedOptionsInput || !isColumnOptionMap(facetedOptionsInput))
          return config;

        final = { ...final, facetedOptions: facetedOptionsInput };
      }

      // Set faceted min/max values, if exists
      if (config.type === "number" && faceted) {
        const minMaxTuple = faceted[config.id as NumberColumnIds<TColumns>];
        if (!minMaxTuple || !isMinMaxTuple(minMaxTuple)) return config;

        final = {
          ...final,
          min: minMaxTuple[0],
          max: minMaxTuple[1],
        };
      }

      return final;
    });

    return createColumns(data, enhancedConfigs, strategy);
  }, [data, columnsConfig, options, faceted, strategy]);

  const actions: DataTableFilterActions<TContext> = useMemo(
    () => ({
      addFilterValue<TData, TType extends OptionBasedColumnDataType>(
        column: Column<TData, TType>,
        values: FilterModel<TType>["values"],
        context?: TContext,
      ) {
        setFilters(
          (prev) => filterOperations.addFilterValue(prev, column, values),
          context,
        );
      },

      removeFilterValue<TData, TType extends OptionBasedColumnDataType>(
        column: Column<TData, TType>,
        value: FilterModel<TType>["values"],
        context?: TContext,
      ) {
        setFilters(
          (prev) => filterOperations.removeFilterValue(prev, column, value),
          context,
        );
      },

      setFilterValue<TData, TType extends ColumnDataType>(
        column: Column<TData, TType>,
        values: FilterModel<TType>["values"],
        context?: TContext,
      ) {
        setFilters(
          (prev) => filterOperations.setFilterValue(prev, column, values),
          context,
        );
      },

      setFilterOperator<TType extends ColumnDataType>(
        columnId: string,
        operator: FilterModel<TType>["operator"],
        context?: TContext,
      ) {
        setFilters(
          (prev) =>
            filterOperations.setFilterOperator(prev, columnId, operator),
          context,
        );
      },

      removeFilter(columnId: string, context?: TContext) {
        setFilters(
          (prev) => filterOperations.removeFilter(prev, columnId),
          context,
        );
      },

      removeAllFilters(context?: TContext) {
        setFilters((prev) => filterOperations.removeAllFilters(prev), context);
      },

      batch(
        callback: (batchActions: DataTableFilterBatchActions) => void,
        context?: TContext,
      ) {
        setFilters((prevFilters) => {
          // Start with current state
          let transactionFilters = prevFilters;

          // Create batch actions that apply operations to transaction state
          const batchActions: BatchFilterOperations = {
            addFilterValue<TData, TType extends OptionBasedColumnDataType>(
              column: Column<TData, TType>,
              values: FilterModel<TType>["values"],
            ) {
              transactionFilters = filterOperations.addFilterValue(
                transactionFilters,
                column,
                values,
              );
            },

            removeFilterValue<TData, TType extends OptionBasedColumnDataType>(
              column: Column<TData, TType>,
              value: FilterModel<TType>["values"],
            ) {
              transactionFilters = filterOperations.removeFilterValue(
                transactionFilters,
                column,
                value,
              );
            },

            setFilterValue<TData, TType extends ColumnDataType>(
              column: Column<TData, TType>,
              values: FilterModel<TType>["values"],
            ) {
              transactionFilters = filterOperations.setFilterValue(
                transactionFilters,
                column,
                values,
              );
            },

            setFilterOperator<TType extends ColumnDataType>(
              columnId: string,
              operator: FilterModel<TType>["operator"],
            ) {
              transactionFilters = filterOperations.setFilterOperator(
                transactionFilters,
                columnId,
                operator,
              );
            },

            removeFilter(columnId: string) {
              transactionFilters = filterOperations.removeFilter(
                transactionFilters,
                columnId,
              );
            },

            removeAllFilters() {
              transactionFilters =
                filterOperations.removeAllFilters(transactionFilters);
            },
          };

          // Execute the callback with batch actions
          callback(batchActions);

          // Return the final transaction state
          return transactionFilters;
        }, context);
      },
    }),
    [setFilters],
  );

  return { columns, filters, actions, strategy, entityName }; // columns is Column<TData>[]
}

export function createTypedDataTableFilters<TContext>() {
  return function useTypedDataTableFilters<
    TData,
    TColumns extends ReadonlyArray<ColumnConfig<TData, any, any, any>>,
    TStrategy extends FilterStrategy,
  >(
    options: DataTableFiltersOptions<TData, TColumns, TStrategy, TContext>,
  ): DataTableFiltersInstance<TData, TStrategy, TContext> {
    return useDataTableFilters<TData, TColumns, TStrategy, TContext>(options);
  };
}

import { getValidNumber } from "./helpers";

export function intersection<T>(a: T[], b: T[]): T[] {
  return a.filter((x) => b.includes(x));
}

/**
 * Computes a stable hash string for any value using deep inspection.
 * This function recursively builds a string for primitives, arrays, and objects.
 * It uses a cache (WeakMap) to avoid rehashing the same object twice, which is
 * particularly beneficial if an object appears in multiple places.
 */
function deepHash(value: any, cache = new WeakMap<object, string>()): string {
  // Handle primitives and null/undefined.
  if (value === null) return "null";
  if (value === undefined) return "undefined";
  const type = typeof value;
  if (type === "number" || type === "boolean" || type === "string") {
    return `${type}:${value.toString()}`;
  }
  if (type === "function") {
    // Note: using toString for functions.
    return `function:${value.toString()}`;
  }

  // For objects and arrays, use caching to avoid repeated work.
  if (type === "object") {
    // If we’ve seen this object before, return the cached hash.
    if (cache.has(value)) {
      return cache.get(value)!;
    }
    let hash: string;
    if (Array.isArray(value)) {
      // Compute hash for each element in order.
      hash = `array:[${value.map((v) => deepHash(v, cache)).join(",")}]`;
    } else {
      // For objects, sort keys to ensure the representation is stable.
      const keys = Object.keys(value).sort();
      const props = keys
        .map((k) => `${k}:${deepHash(value[k], cache)}`)
        .join(",");
      hash = `object:{${props}}`;
    }
    cache.set(value, hash);
    return hash;
  }

  // Fallback if no case matched.
  return `${type}:${value.toString()}`;
}

/**
 * Performs deep equality check for any two values.
 * This recursively checks primitives, arrays, and plain objects.
 */
function deepEqual(a: any, b: any): boolean {
  // Check strict equality first.
  if (a === b) return true;
  // If types differ, they’re not equal.
  if (typeof a !== typeof b) return false;
  if (a === null || b === null || a === undefined || b === undefined)
    return false;

  // Check arrays.
  if (Array.isArray(a)) {
    if (!Array.isArray(b) || a.length !== b.length) return false;
    for (let i = 0; i < a.length; i++) {
      if (!deepEqual(a[i], b[i])) return false;
    }
    return true;
  }

  // Check objects.
  if (typeof a === "object") {
    if (typeof b !== "object") return false;
    const aKeys = Object.keys(a).sort();
    const bKeys = Object.keys(b).sort();
    if (aKeys.length !== bKeys.length) return false;
    for (let i = 0; i < aKeys.length; i++) {
      if (aKeys[i] !== bKeys[i]) return false;
      if (!deepEqual(a[aKeys[i]!], b[bKeys[i]!])) return false;
    }
    return true;
  }

  // For any other types (should be primitives by now), use strict equality.
  return false;
}

/**
 * Returns a new array containing only the unique values from the input array.
 * Uniqueness is determined by deep equality.
 *
 * @param arr - The array of values to be filtered.
 * @returns A new array with duplicates removed.
 */
export function uniq<T>(arr: T[]): T[] {
  // Use a Map where key is the deep hash and value is an array of items sharing the same hash.
  const seen = new Map<string, T[]>();
  const result: T[] = [];

  for (const item of arr) {
    const hash = deepHash(item);
    if (seen.has(hash)) {
      // There is a potential duplicate; check the stored items with the same hash.
      const itemsWithHash = seen.get(hash)!;
      let duplicateFound = false;
      for (const existing of itemsWithHash) {
        if (deepEqual(existing, item)) {
          duplicateFound = true;
          break;
        }
      }
      if (!duplicateFound) {
        itemsWithHash.push(item);
        result.push(item);
      }
    } else {
      // First time this hash appears.
      seen.set(hash, [item]);
      result.push(item);
    }
  }

  return result;
}

export function take<T>(a: T[], n: number): T[] {
  return a.slice(0, n);
}

export function flatten<T>(a: T[][]): T[] {
  return a.flat();
}

export function addUniq<T>(arr: T[], values: T[]): T[] {
  return uniq([...arr, ...values]);
}

export function removeUniq<T>(arr: T[], values: T[]): T[] {
  return arr.filter((v) => !values.includes(v));
}

export function isAnyOf<T>(value: T, values: T[]): boolean {
  return values.includes(value);
}

function getValidBigInt(value: any): bigint | undefined {
  if (value === null || value === undefined) return undefined;
  if (typeof value !== "bigint") return undefined;
  return value;
}

/**
 * Get the maximum value from an array of numbers.
 * Ignores invalid entries (null/undefined/NaN or non-numbers) via `getValidNumber`,
 * so it's safe with `noUncheckedIndexedAccess` and sparse arrays.
 *
 * @param values - Array of numbers (may contain holes)
 * @returns The largest valid number, or -Infinity if none are valid.
 * @example
 * max([1, 3, 2]) // => 3
 * max([])        // => -Infinity
 */
export function max(values: readonly number[]): number;
/**
 * Get the maximum value from an array of bigints.
 * Ignores invalid entries (null/undefined or non-bigints),
 * so it's safe with `noUncheckedIndexedAccess` and sparse arrays.
 *
 * @param values - Array of bigints (may contain holes)
 * @returns The largest valid bigint, or -Infinity if none are valid.
 * @example
 * max([1n, 3n, 2n]) // => 3n
 * max([])           // => -Infinity
 */
export function max(values: readonly bigint[]): bigint;
export function max(
  values: readonly number[] | readonly bigint[],
): number | bigint {
  let found = false;

  // Check if we're dealing with numbers or bigints by looking at the first valid value
  let isNumberArray = false;
  let isBigIntArray = false;

  for (let i = 0; i < values.length; i++) {
    const value = values[i];
    if (getValidNumber(value) !== undefined) {
      isNumberArray = true;
      break;
    }
    if (getValidBigInt(value) !== undefined) {
      isBigIntArray = true;
      break;
    }
  }

  if (isNumberArray) {
    let m = Number.NEGATIVE_INFINITY;
    for (let i = 0; i < values.length; i++) {
      const v = getValidNumber(values[i] as any);
      if (v !== undefined) {
        if (v > m) m = v;
        found = true;
      }
    }
    return found ? m : Number.NEGATIVE_INFINITY;
  }

  // BigInt array
  let m: bigint | number = Number.NEGATIVE_INFINITY;
  for (let i = 0; i < values.length; i++) {
    const v = getValidBigInt(values[i] as any);
    if (v !== undefined) {
      if (!found) {
        m = v;
        found = true;
      } else if (typeof m === "bigint" && v > m) {
        m = v;
      }
    }
  }
  return found ? m : Number.NEGATIVE_INFINITY;
}

/**
 * Get the minimum value from an array of numbers.
 * Ignores invalid entries (null/undefined/NaN or non-numbers) via `getValidNumber`,
 * so it's safe with `noUncheckedIndexedAccess` and sparse arrays.
 *
 * @param values - Array of numbers (may contain holes)
 * @returns The smallest valid number, or Infinity if none are valid.
 * @example
 * min([1, 3, 2]) // => 1
 * min([])        // => Infinity
 */
export function min(values: readonly number[]): number;
/**
 * Get the minimum value from an array of bigints.
 * Ignores invalid entries (null/undefined or non-bigints),
 * so it's safe with `noUncheckedIndexedAccess` and sparse arrays.
 *
 * @param values - Array of bigints (may contain holes)
 * @returns The smallest valid bigint, or Infinity if none are valid.
 * @example
 * min([1n, 3n, 2n]) // => 1n
 * min([])           // => Infinity
 */
export function min(values: readonly bigint[]): bigint;
export function min(
  values: readonly number[] | readonly bigint[],
): number | bigint {
  let found = false;

  // Check if we're dealing with numbers or bigints by looking at the first valid value
  let isNumberArray = false;
  let isBigIntArray = false;

  for (let i = 0; i < values.length; i++) {
    const value = values[i];
    if (getValidNumber(value) !== undefined) {
      isNumberArray = true;
      break;
    }
    if (getValidBigInt(value) !== undefined) {
      isBigIntArray = true;
      break;
    }
  }

  if (isNumberArray) {
    let m = Number.POSITIVE_INFINITY;
    for (let i = 0; i < values.length; i++) {
      const v = getValidNumber(values[i] as any);
      if (v !== undefined) {
        if (v < m) m = v;
        found = true;
      }
    }
    return found ? m : Number.POSITIVE_INFINITY;
  }

  // BigInt array
  let m: bigint | number = Number.POSITIVE_INFINITY;
  for (let i = 0; i < values.length; i++) {
    const v = getValidBigInt(values[i] as any);
    if (v !== undefined) {
      if (!found) {
        m = v;
        found = true;
      } else if (typeof m === "bigint" && v < m) {
        m = v;
      }
    }
  }
  return found ? m : Number.POSITIVE_INFINITY;
}

/**
 * Get both the minimum and maximum values from an array of numbers in a single pass.
 * Ignores invalid entries via `getValidNumber`, making it safe with `noUncheckedIndexedAccess`
 * and efficient for sparse/large arrays.
 *
 * @param values - Array of numbers (may contain holes)
 * @returns A tuple [min, max], or [Infinity, -Infinity] if none are valid.
 * @example
 * minMax([3, -2, 7, 0]) // => [-2, 7]
 * minMax([])            // => [Infinity, -Infinity]
 */
export function minMax(values: readonly number[]): [number, number];
/**
 * Get both the minimum and maximum values from an array of bigints in a single pass.
 * Ignores invalid entries via `getValidBigInt`, making it safe with `noUncheckedIndexedAccess`
 * and efficient for sparse/large arrays.
 *
 * @param values - Array of bigints (may contain holes)
 * @returns A tuple [min, max], or [Infinity, -Infinity] if none are valid.
 * @example
 * minMax([3n, -2n, 7n, 0n]) // => [-2n, 7n]
 * minMax([])                // => [Infinity, -Infinity]
 */
export function minMax(values: readonly bigint[]): [bigint, bigint];
export function minMax(
  values: readonly number[] | readonly bigint[],
): [number, number] | [bigint, bigint] {
  let found = false;

  // Check if we're dealing with numbers or bigints by looking at the first valid value
  let isNumberArray = false;
  let isBigIntArray = false;

  for (let i = 0; i < values.length; i++) {
    const value = values[i];
    if (getValidNumber(value) !== undefined) {
      isNumberArray = true;
      break;
    }
    if (getValidBigInt(value) !== undefined) {
      isBigIntArray = true;
      break;
    }
  }

  if (isNumberArray) {
    let minVal = Number.POSITIVE_INFINITY;
    let maxVal = Number.NEGATIVE_INFINITY;

    for (let i = 0; i < values.length; i++) {
      const v = getValidNumber(values[i] as any);
      if (v !== undefined) {
        if (v < minVal) minVal = v;
        if (v > maxVal) maxVal = v;
        found = true;
      }
    }

    return found
      ? [minVal, maxVal]
      : [Number.POSITIVE_INFINITY, Number.NEGATIVE_INFINITY];
  }

  // BigInt array
  let minVal: bigint | number = Number.POSITIVE_INFINITY;
  let maxVal: bigint | number = Number.NEGATIVE_INFINITY;

  for (let i = 0; i < values.length; i++) {
    const v = getValidBigInt(values[i] as any);
    if (v !== undefined) {
      if (!found) {
        minVal = v;
        maxVal = v;
        found = true;
      } else {
        if (typeof minVal === "bigint" && v < minVal) minVal = v;
        if (typeof maxVal === "bigint" && v > maxVal) maxVal = v;
      }
    }
  }

  return found
    ? [minVal as bigint, maxVal as bigint]
    : [Number.POSITIVE_INFINITY, Number.NEGATIVE_INFINITY];
}

import {
  endOfDay,
  isAfter,
  isBefore,
  isSameDay,
  isWithinInterval,
  startOfDay,
} from "date-fns";

import type { FilterModel } from "../core/types";
import { dateFilterOperators } from "../core/operators";
import { intersection } from "./array";
import { getValidBigInt, getValidNumber, isValidNumber } from "./helpers";

export function optionFilterFn(
  inputData: string,
  filterValue: FilterModel<"option">,
) {
  if (!inputData) return false;
  if (filterValue.values.length === 0) return true;

  const value = inputData.toString().toLowerCase();

  const found = !!filterValue.values.find((v) => v.toLowerCase() === value);

  switch (filterValue.operator) {
    case "is":
    case "is any of":
      return found;
    case "is not":
    case "is none of":
      return !found;
  }
}

export function multiOptionFilterFn(
  inputData: string[],
  filterValue: FilterModel<"multiOption">,
) {
  if (!inputData) return false;

  if (
    filterValue.values.length === 0 ||
    !filterValue.values[0] ||
    filterValue.values[0].length === 0
  )
    return true;

  const values = inputData;
  const filterValues = filterValue.values;

  switch (filterValue.operator) {
    case "include":
    case "include any of":
      return intersection(values, filterValues).length > 0;
    case "exclude":
      return intersection(values, filterValues).length === 0;
    case "exclude if any of":
      return !(intersection(values, filterValues).length > 0);
    case "include all of":
      return intersection(values, filterValues).length === filterValues.length;
    case "exclude if all":
      return !(
        intersection(values, filterValues).length === filterValues.length
      );
  }
}

export function dateFilterFn(
  inputData: Date,
  filterValue: FilterModel<"date">,
) {
  if (!filterValue || filterValue.values.length === 0) return true;

  if (
    dateFilterOperators[filterValue.operator].target === "single" &&
    filterValue.values.length > 1
  )
    throw new Error("Singular operators require at most one filter value");

  if (
    filterValue.operator in ["is between", "is not between"] &&
    filterValue.values.length !== 2
  )
    throw new Error("Plural operators require two filter values");

  const filterVals = filterValue.values;
  const d1 = filterVals[0]!;
  const d2 = filterVals[1]!;

  const value = inputData;

  switch (filterValue.operator) {
    case "is":
      return isSameDay(value, d1);
    case "is not":
      return !isSameDay(value, d1);
    case "is before":
      return isBefore(value, startOfDay(d1));
    case "is on or after":
      return isSameDay(value, d1) || isAfter(value, startOfDay(d1));
    case "is after":
      return isAfter(value, startOfDay(d1));
    case "is on or before":
      return isSameDay(value, d1) || isBefore(value, startOfDay(d1));
    case "is between":
      return isWithinInterval(value, {
        start: startOfDay(d1),
        end: endOfDay(d2),
      });
    case "is not between":
      return !isWithinInterval(value, {
        start: startOfDay(filterValue.values[0]!),
        end: endOfDay(filterValue.values[1]!),
      });
  }
}

export function textFilterFn(
  inputData: string,
  filterValue: FilterModel<"text">,
) {
  if (!filterValue || filterValue.values.length === 0) return true;

  const value = inputData.toLowerCase().trim();
  const filterStr = filterValue.values[0]!.toLowerCase().trim();

  if (filterStr === "") return true;

  const found = value.includes(filterStr);

  switch (filterValue.operator) {
    case "contains":
      return found;
    case "does not contain":
      return !found;
  }
}

export function numberFilterFn(
  inputData: number,
  filterValue: FilterModel<"number">,
): boolean {
  // Early exit conditions
  if (!filterValue || !filterValue.values || filterValue.values.length === 0) {
    return true;
  }

  const value = inputData;
  const filterVal = getValidNumber(filterValue.values[0]);

  // If the primary filter value is invalid, no filtering applies
  if (filterVal === undefined) {
    return true;
  }

  // Input validation - if input data is not a valid number, handle appropriately
  if (!isValidNumber(value)) {
    // NaN input data never matches any filter (NaN !== NaN)
    return false;
  }

  switch (filterValue.operator) {
    case "is":
      return value === filterVal;

    case "is not":
      return value !== filterVal;

    case "is greater than":
      // Handle Infinity edge cases
      if (filterVal === Number.POSITIVE_INFINITY) return false; // Nothing is greater than Infinity
      if (filterVal === Number.NEGATIVE_INFINITY) return true; // Everything is greater than -Infinity
      return value > filterVal;

    case "is greater than or equal to":
      if (filterVal === Number.POSITIVE_INFINITY)
        return value === Number.POSITIVE_INFINITY; // Only Infinity >= Infinity
      if (filterVal === Number.NEGATIVE_INFINITY) return true; // Everything >= -Infinity
      return value >= filterVal;

    case "is less than":
      if (filterVal === Number.NEGATIVE_INFINITY) return false; // Nothing is less than -Infinity
      if (filterVal === Number.POSITIVE_INFINITY)
        return value !== Number.POSITIVE_INFINITY; // Everything except Infinity < Infinity
      return value < filterVal;

    case "is less than or equal to":
      if (filterVal === Number.NEGATIVE_INFINITY)
        return value === Number.NEGATIVE_INFINITY; // Only -Infinity <= -Infinity
      if (filterVal === Number.POSITIVE_INFINITY) return true; // Everything <= Infinity
      return value <= filterVal;

    case "is between": {
      const lowerBound = getValidNumber(filterValue.values[0]);
      const upperBound = getValidNumber(filterValue.values[1]);

      // If either bound is invalid, no filtering applies
      if (lowerBound === undefined || upperBound === undefined) {
        return true;
      }

      // Handle the case where bounds might be reversed
      const actualLower = Math.min(lowerBound, upperBound);
      const actualUpper = Math.max(lowerBound, upperBound);

      // Special handling for infinite bounds
      if (
        actualLower === Number.NEGATIVE_INFINITY &&
        actualUpper === Number.POSITIVE_INFINITY
      ) {
        return true; // Everything is between -∞ and +∞
      }
      if (
        actualLower === Number.POSITIVE_INFINITY ||
        actualUpper === Number.NEGATIVE_INFINITY
      ) {
        return false; // Invalid range
      }

      return value >= actualLower && value <= actualUpper;
    }

    case "is not between": {
      const lowerBound = getValidNumber(filterValue.values[0]);
      const upperBound = getValidNumber(filterValue.values[1]);

      // If either bound is invalid, no filtering applies
      if (lowerBound === undefined || upperBound === undefined) {
        return true;
      }

      // Handle the case where bounds might be reversed
      const actualLower = Math.min(lowerBound, upperBound);
      const actualUpper = Math.max(lowerBound, upperBound);

      // Special handling for infinite bounds
      if (
        actualLower === Number.NEGATIVE_INFINITY &&
        actualUpper === Number.POSITIVE_INFINITY
      ) {
        return false; // Nothing is outside -∞ to +∞
      }
      if (
        actualLower === Number.POSITIVE_INFINITY ||
        actualUpper === Number.NEGATIVE_INFINITY
      ) {
        return true; // Invalid range means everything is "not between"
      }

      return value < actualLower || value > actualUpper;
    }

    default:
      return true;
  }
}

export function bigIntFilterFn(
  inputData: bigint,
  filterValue: FilterModel<"bigint">,
): boolean {
  // Early exit conditions
  if (!filterValue || !filterValue.values || filterValue.values.length === 0) {
    return true;
  }

  const value = inputData;
  const filterVal = getValidBigInt(filterValue.values[0]);

  if (filterVal === undefined) {
    return true;
  }

  if (typeof value !== "bigint") {
    return false;
  }

  switch (filterValue.operator) {
    case "is":
      return value === filterVal;

    case "is not":
      return value !== filterVal;

    case "is greater than":
      return value > filterVal;

    case "is greater than or equal to":
      return value >= filterVal;

    case "is less than":
      return value < filterVal;

    case "is less than or equal to":
      return value <= filterVal;

    case "is between": {
      const lowerBound = getValidBigInt(filterValue.values[0]);
      const upperBound = getValidBigInt(filterValue.values[1]);

      if (lowerBound === undefined || upperBound === undefined) {
        return true;
      }

      const actualLower = lowerBound < upperBound ? lowerBound : upperBound;
      const actualUpper = lowerBound < upperBound ? upperBound : lowerBound;

      return value >= actualLower && value <= actualUpper;
    }

    case "is not between": {
      const lowerBound = getValidBigInt(filterValue.values[0]);
      const upperBound = getValidBigInt(filterValue.values[1]);

      if (lowerBound === undefined || upperBound === undefined) {
        return true;
      }

      const actualLower = lowerBound < upperBound ? lowerBound : upperBound;
      const actualUpper = lowerBound < upperBound ? upperBound : lowerBound;

      return value < actualLower || value > actualUpper;
    }

    default:
      return true;
  }
}

export function booleanFilterFn(
  inputData: boolean,
  filterValue: FilterModel<"boolean">,
) {
  if (!filterValue || filterValue.values.length === 0) return true;

  if (filterValue.values.some((v) => typeof v === "undefined"))
    throw new Error("Cannot create boolean filter value from undefined values");

  const value = inputData;
  const filterVal = filterValue.values[0] ?? false;

  switch (filterValue.operator) {
    case "is":
      return value === filterVal;
    case "is not":
      return value !== filterVal;
    default:
      return true;
  }
}

import { isBefore } from "date-fns";

import type { Column, ColumnOption, FiltersState } from "../core/types";
import {
  booleanFilterFn,
  dateFilterFn,
  multiOptionFilterFn,
  numberFilterFn,
  optionFilterFn,
  textFilterFn,
} from "./filter-fns";

export function getColumn<TData>(columns: Column<TData>[], id: string) {
  const column = columns.find((c) => c.id === id);

  if (!column) {
    throw new Error(`Column with id ${id} not found`);
  }

  return column;
}

export function createNumberFilterValue(
  values: number[] | undefined,
): number[] {
  if (!values || values.length === 0 || values[0] === undefined) return [];
  if (values.length === 1) return [values[0]];
  if (values.length === 2) return createNumberRange(values);
  return [values[0], values[1]!];
}

export function createBigIntFilterValue(
  values: bigint[] | undefined,
): bigint[] {
  if (!values || values.length === 0 || values[0] === undefined) return [];
  if (values.length === 1) return [values[0]];
  if (values.length === 2) return createBigIntRange(values);
  throw new Error("Cannot create bigint filter value from more than 2 values");
}

export function createDateFilterValue(
  values: [Date, Date] | [Date] | [] | undefined,
) {
  if (!values || values.length === 0) return [];
  if (values.length === 1) return [values[0]];
  if (values.length === 2) return createDateRange(values);
  throw new Error("Cannot create date filter value from more than 2 values");
}

export function createDateRange(values: [Date, Date]) {
  const [a, b] = values;
  const [min, max] = isBefore(a, b) ? [a, b] : [b, a];

  return [min, max];
}

export function createNumberRange(values: number[] | undefined) {
  let a = 0;
  let b = 0;

  if (!values || values.length === 0) return [a, b];
  if (values.length === 1) {
    a = values[0]!;
  } else {
    a = values[0]!;
    b = values[1]!;
  }

  const [min, max] = a < b ? [a, b] : [b, a];

  return [min, max];
}

export function createBigIntRange(values: bigint[] | undefined) {
  let a = 0n;
  let b = 0n;

  if (!values || values.length === 0) return [a, b];
  if (values.length === 1) {
    a = values[0]!;
  } else {
    a = values[0]!;
    b = values[1]!;
  }

  const [min, max] = a < b ? [a, b] : [b, a];

  return [min, max];
}

export function isColumnOption(value: unknown): value is ColumnOption {
  return (
    typeof value === "object" &&
    value !== null &&
    "value" in value &&
    "label" in value
  );
}

export function isColumnOptionArray(value: unknown): value is ColumnOption[] {
  return Array.isArray(value) && value.every(isColumnOption);
}

export function isStringArray(value: unknown): value is string[] {
  return Array.isArray(value) && value.every((v) => typeof v === "string");
}

export function isColumnOptionMap(
  value: unknown,
): value is Map<string, number> {
  if (!(value instanceof Map)) {
    return false;
  }
  for (const key of value.keys()) {
    if (typeof key !== "string") {
      return false;
    }
  }
  for (const val of value.values()) {
    if (typeof val !== "number") {
      return false;
    }
  }
  return true;
}

export function isMinMaxTuple(value: unknown): value is [number, number] {
  return (
    Array.isArray(value) &&
    value.length === 2 &&
    typeof value[0] === "number" &&
    typeof value[1] === "number"
  );
}
export function getValidNumber(value: any): number | undefined {
  if (value === null || value === undefined) return undefined;
  if (typeof value !== "number") return undefined;
  if (Number.isNaN(value)) return undefined;

  return value; // This includes Infinity and -Infinity, which are valid
}

export function isValidNumber(value: any): value is number {
  return typeof value === "number" && !Number.isNaN(value);
}

export function getValidBigInt(value: any): bigint | undefined {
  if (value === null || value === undefined) return undefined;
  if (typeof value === "bigint") return value;
  if (typeof value === "string" || typeof value === "number") {
    try {
      return BigInt(value);
    } catch {
      return undefined;
    }
  }
  return undefined;
}

export function filterRow(row: any, filters: FiltersState) {
  for (const filter of filters) {
    const cell = row[filter.columnId];

    if (filter.type === "text") {
      if (!textFilterFn(cell, filter)) {
        return false;
      }
    } else if (filter.type === "number") {
      if (!numberFilterFn(cell, filter)) {
        return false;
      }
    } else if (filter.type === "date") {
      if (!dateFilterFn(cell, filter)) {
        return false;
      }
    } else if (filter.type === "boolean") {
      if (!booleanFilterFn(cell, filter)) {
        return false;
      }
    } else if (filter.type === "option") {
      if (!optionFilterFn(cell, filter)) {
        return false;
      }
    } else if (filter.type === "multiOption") {
      if (!multiOptionFilterFn(cell, filter)) {
        return false;
      }
    } else {
      throw new Error(`Unknown filter type: ${filter.type}`);
    }
  }

  return true;
}

export function filterData<TData>(
  data: TData[],
  filters: FiltersState,
): TData[] {
  return data.filter((row) => filterRow(row, filters));
}

// Overloads for up to 6 dependencies
// TypeScript can't infer the exact tuple types when destructuring
export function memo<T1, TResult>(
  getDeps: () => readonly [T1],
  compute: (deps: readonly [T1]) => TResult,
  options: { key: string },
): () => TResult;

// 2 dependencies
export function memo<T1, T2, TResult>(
  getDeps: () => readonly [T1, T2],
  compute: (deps: readonly [T1, T2]) => TResult,
  options: { key: string },
): () => TResult;

// 3 dependencies
export function memo<T1, T2, T3, TResult>(
  getDeps: () => readonly [T1, T2, T3],
  compute: (deps: readonly [T1, T2, T3]) => TResult,
  options: { key: string },
): () => TResult;

// 4 dependencies
export function memo<T1, T2, T3, T4, TResult>(
  getDeps: () => readonly [T1, T2, T3, T4],
  compute: (deps: readonly [T1, T2, T3, T4]) => TResult,
  options: { key: string },
): () => TResult;

// 5 dependencies
export function memo<T1, T2, T3, T4, T5, TResult>(
  getDeps: () => readonly [T1, T2, T3, T4, T5],
  compute: (deps: readonly [T1, T2, T3, T4, T5]) => TResult,
  options: { key: string },
): () => TResult;

// General fallback for 6+ dependencies
export function memo<TDeps extends readonly any[], TResult>(
  getDeps: () => TDeps,
  compute: (deps: TDeps) => TResult,
  options: { key: string },
): () => TResult;

export function memo<TDeps extends readonly any[], TResult>(
  getDeps: () => TDeps,
  compute: (deps: TDeps) => TResult,
  options: { key: string },
): () => TResult {
  let prevDeps: TDeps | undefined;
  let cachedResult: TResult | undefined;

  return () => {
    const deps = getDeps();

    // If no previous deps or deps have changed, recompute
    if (!prevDeps || !shallowEqual(prevDeps, deps)) {
      cachedResult = compute(deps);
      prevDeps = deps;
    }

    return cachedResult!;
  };
}

function shallowEqual<T>(arr1: readonly T[], arr2: readonly T[]): boolean {
  if (arr1 === arr2) return true;
  if (arr1.length !== arr2.length) return false;

  for (let i = 0; i < arr1.length; i++) {
    if (arr1[i] !== arr2[i]) return false;
  }
  return true;
}

import type {
  ColumnOption,
  OrderDirection,
  TBuiltInOrderFn,
  TBuiltInOrderFnName,
  TCustomOrderFn,
  TOrderFnArg,
  TOrderFns,
} from "../core/types";

/**
 * Built-in order function that sorts column options by their count property.
 * Treats undefined counts as 0.
 *
 * @param a - First column option to compare
 * @param b - Second column option to compare
 * @param direction - Sort direction ('asc' for ascending, 'desc' for descending)
 * @returns Negative number if a should come before b, positive if after, 0 if equal
 *
 * @example
 * ```typescript
 * // Sort by count ascending
 * const result = count(
 *   { value: 'a', label: 'A', count: 5 },
 *   { value: 'b', label: 'B', count: 3 },
 *   'asc'
 * ) // Returns -2 (3 - 5)
 * ```
 */
function count(a: ColumnOption, b: ColumnOption, direction: OrderDirection) {
  const x = a.count ?? 0;
  const y = b.count ?? 0;

  return direction === "asc" ? x - y : y - x;
}

/**
 * Built-in order function that sorts column options by their label property.
 * Performs case-insensitive comparison using localeCompare.
 *
 * @param a - First column option to compare
 * @param b - Second column option to compare
 * @param direction - Sort direction ('asc' for ascending, 'desc' for descending)
 * @returns Negative number if a should come before b, positive if after, 0 if equal
 *
 * @example
 * ```typescript
 * // Sort by label ascending (case-insensitive)
 * const result = label(
 *   { value: 'a', label: 'Apple' },
 *   { value: 'b', label: 'banana' },
 *   'asc'
 * ) // Returns negative number ('apple' < 'banana')
 * ```
 */
function label(a: ColumnOption, b: ColumnOption, direction: OrderDirection) {
  const x = a.label.toLowerCase();
  const y = b.label.toLowerCase();

  return direction === "asc" ? x.localeCompare(y) : y.localeCompare(x);
}

/**
 * Collection of built-in order functions available for sorting column options.
 * Each function takes two ColumnOptions and an OrderDirection, returning a comparison result.
 *
 * @example
 * ```typescript
 * // Use built-in count function
 * const sortedOptions = options.sort((a, b) => orderFns.count(a, b, 'desc'))
 * ```
 */
export const orderFns = {
  count,
  label,
} as const satisfies Record<string, TBuiltInOrderFn>;

/**
 * Applies multiple order functions to sort an array of column options.
 * Functions are applied in sequence - if the first comparison returns 0 (equal),
 * the next function is tried, and so on. This mimics SQL's ORDER BY behavior
 * with multiple columns.
 *
 * @param orderFns - Array of order functions to apply in sequence
 * @param options - Array of column options to sort
 * @returns New sorted array of column options
 *
 * @example
 * ```typescript
 * // Sort by count descending, then by label ascending for ties
 * const orderFunctions = [
 *   (a, b) => orderFns.count(a, b, 'desc'),
 *   (a, b) => orderFns.label(a, b, 'asc')
 * ]
 * const sorted = applyOrderFns(orderFunctions, options)
 * ```
 */
export function applyOrderFns(
  orderFns: TOrderFns,
  options: ColumnOption[],
): ColumnOption[] {
  return options.sort((a, b) => {
    for (const orderFn of orderFns) {
      const result = orderFn(a, b);
      if (result !== 0) {
        return result; // First non-zero result wins
      }
    }
    return 0; // All comparisons were equal
  });
}

// Type guards

/**
 * Type guard that checks if a value is a valid built-in order function name.
 *
 * @param value - Value to check
 * @returns True if value is a valid built-in order function name
 *
 * @example
 * ```typescript
 * if (isBuiltInOrderFnName('count')) {
 *   // value is guaranteed to be 'count' | 'label'
 * }
 * ```
 */
export function isBuiltInOrderFnName(
  value: unknown,
): value is TBuiltInOrderFnName {
  return typeof value === "string" && value in orderFns;
}

/**
 * Type guard that checks if a value is a valid order direction.
 *
 * @param value - Value to check
 * @returns True if value is 'asc' or 'desc'
 *
 * @example
 * ```typescript
 * if (isOrderDirection(userInput)) {
 *   // userInput is guaranteed to be 'asc' | 'desc'
 * }
 * ```
 */
export function isOrderDirection(value: unknown): value is OrderDirection {
  return typeof value === "string" && (value === "asc" || value === "desc");
}

/**
 * Type guard that checks if a value is a valid custom order function.
 * A valid custom order function must be a function that accepts exactly 2 parameters.
 *
 * @param value - Value to check
 * @returns True if value is a function with exactly 2 parameters
 *
 * @example
 * ```typescript
 * const customFn = (a: ColumnOption, b: ColumnOption) => a.value.localeCompare(b.value)
 * if (isCustomOrderFn(customFn)) {
 *   // customFn is guaranteed to be TCustomOrderFn
 * }
 * ```
 */
export function isCustomOrderFn(value: unknown): value is TCustomOrderFn {
  return typeof value === "function" && value.length === 2;
}

/**
 * Type guard that checks if a value is a valid built-in order function tuple.
 * A valid tuple consists of [functionName, direction] where functionName is a built-in
 * function name and direction is 'asc' or 'desc'.
 *
 * @param value - Value to check
 * @returns True if value is a valid [TBuiltInOrderFnName, OrderDirection] tuple
 *
 * @example
 * ```typescript
 * if (isBuiltInOrderFnTuple(['count', 'asc'])) {
 *   // value is guaranteed to be ['count' | 'label', 'asc' | 'desc']
 * }
 * ```
 */
export function isBuiltInOrderFnTuple(
  value: unknown,
): value is [TBuiltInOrderFnName, OrderDirection] {
  return (
    Array.isArray(value) &&
    value.length === 2 &&
    isBuiltInOrderFnName(value[0]) &&
    isOrderDirection(value[1])
  );
}

/**
 * Type guard that checks if a value is any valid order function argument.
 * Accepts either a built-in order function tuple or a custom order function.
 *
 * @param value - Value to check
 * @returns True if value is a valid order function argument
 *
 * @example
 * ```typescript
 * // Valid arguments:
 * isOrderFnArg(['count', 'asc']) // true - built-in tuple
 * isOrderFnArg((a, b) => a.value.localeCompare(b.value)) // true - custom function
 * isOrderFnArg('invalid') // false
 * ```
 */
export function isOrderFnArg(value: unknown): value is TOrderFnArg {
  return isBuiltInOrderFnTuple(value) || isCustomOrderFn(value);
}

import type {
  ColumnConfig,
  ColumnDataType,
  ColumnMeta,
  ColumnOption,
  OrderDirection,
  TAccessorFn,
  TBuiltInOrderFnName,
  TCustomOrderFn,
  TOrderFnArg,
  TOrderFns,
  TTransformOptionsFn,
  TTransformValueToOptionFn,
} from "../types";
import { isAnyOf } from "../../lib/array";
import {
  isBuiltInOrderFnName,
  isBuiltInOrderFnTuple,
  isCustomOrderFn,
  isOrderDirection,
  orderFns,
} from "../../lib/order-fns";

export class ColumnConfigBuilder<
  TData,
  TType extends ColumnDataType = any,
  TVal = unknown,
  TId extends string = string,
> {
  private config: Partial<ColumnConfig<TData, TType, TVal, TId>>;

  constructor(type: TType) {
    this.config = { type } as Partial<ColumnConfig<TData, TType, TVal, TId>>;
  }

  private clone(): ColumnConfigBuilder<TData, TType, TVal, TId> {
    const newInstance = new ColumnConfigBuilder<TData, TType, TVal, TId>(
      this.config.type as TType,
    );
    newInstance.config = { ...this.config };
    return newInstance;
  }

  id<TNewId extends string>(
    value: TNewId,
  ): ColumnConfigBuilder<TData, TType, TVal, TNewId> {
    const newInstance = this.clone() as ColumnConfigBuilder<any, any, any, any>;
    newInstance.config.id = value;
    return newInstance as ColumnConfigBuilder<TData, TType, TVal, TNewId>;
  }

  accessor<TNewVal>(
    accessor: TAccessorFn<TData, TNewVal>,
  ): ColumnConfigBuilder<TData, TType, TNewVal, TId> {
    const newInstance = this.clone() as ColumnConfigBuilder<any, any, any, any>;
    newInstance.config.accessor = accessor;
    return newInstance as ColumnConfigBuilder<TData, TType, TNewVal, TId>;
  }

  displayName(value: string): ColumnConfigBuilder<TData, TType, TVal, TId> {
    const newInstance = this.clone();
    newInstance.config.displayName = value;
    return newInstance;
  }

  icon(value: any): ColumnConfigBuilder<TData, TType, TVal, TId> {
    const newInstance = this.clone();
    newInstance.config.icon = value;
    return newInstance;
  }

  hidden(value: boolean): ColumnConfigBuilder<TData, TType, TVal, TId> {
    const newInstance = this.clone();
    newInstance.config.hidden = value;
    return newInstance;
  }

  // Number-specific methods
  min(
    value: TType extends "number"
      ? number
      : TType extends "bigint"
        ? bigint
        : never,
  ): this {
    this.validateType(["number", "bigint"], "min()");
    this.config.min = value as any;
    return this;
  }

  max(
    value: TType extends "number"
      ? number
      : TType extends "bigint"
        ? bigint
        : never,
  ): this {
    this.validateType(["number", "bigint"], "max()");
    this.config.max = value as any;
    return this;
  }

  // Option-specific methods
  options(value: ColumnOption[]): this {
    this.validateType(["option", "multiOption"], "options()");
    this.config.options = value as any;
    return this;
  }

  transformValueToOptionFn(fn: TTransformValueToOptionFn<TVal>): this {
    this.validateType(["option", "multiOption"], "transformValueToOptionFn()");
    this.config.transformValueToOptionFn = fn as any;
    return this;
  }

  /**
   * Transforms the computed column options after initial computation, with access to faceted data.
   * This is applied AFTER transformValueToOptionFn and has access to both the computed options array
   * and faceted unique values data.
   *
   * @param fn - Function that receives the computed options and faceted data, returns transformed options
   */
  transformOptionsFn(fn: TTransformOptionsFn): this {
    this.validateType(["option", "multiOption"], "transformOptionsFn()");
    this.config.transformOptionsFn = fn as any;
    return this;
  }

  orderFn(name: TBuiltInOrderFnName, direction: OrderDirection): this;
  orderFn(customFn: TCustomOrderFn): this;
  orderFn(...args: TOrderFnArg[]): this;
  orderFn(...args: any[]): this {
    this.validateType(["option", "multiOption"], "orderFn()");

    const orderFnsToApply: TOrderFns = [];

    // Handle the case where first two args are built-in name and direction
    if (
      args.length === 2 &&
      isBuiltInOrderFnName(args[0]) &&
      isOrderDirection(args[1])
    ) {
      const [name, direction] = args;
      orderFnsToApply.push((a: ColumnOption, b: ColumnOption) =>
        orderFns[name](a, b, direction),
      );
    } else if (args.length === 1 && isCustomOrderFn(args[0])) {
      orderFnsToApply.push(args[0]);
    } else {
      // Handle array/rest syntax - validate each argument
      for (const arg of args) {
        if (isBuiltInOrderFnTuple(arg)) {
          const [name, direction] = arg;
          orderFnsToApply.push((a: ColumnOption, b: ColumnOption) =>
            orderFns[name](a, b, direction),
          );
        } else if (isCustomOrderFn(arg)) {
          orderFnsToApply.push(arg);
        } else {
          throw new Error(
            `Invalid argument: ${JSON.stringify(arg)}. Expected built-in function tuple or custom function.`,
          );
        }
      }
    }

    this.config.orderFn = orderFnsToApply as any;
    return this;
  }

  toggledStateName(
    value: string,
  ): ColumnConfigBuilder<
    TData,
    TType extends "boolean" ? TType : never,
    TVal,
    TId
  > {
    if (this.config.type !== "boolean")
      throw new Error(
        "toggledStateName() is only applicable to boolean columns",
      );

    const newInstance = this.clone() as ColumnConfigBuilder<any, any, any, any>;
    newInstance.config.toggledStateName = value;
    return newInstance;
  }

  meta(value: ColumnMeta): ColumnConfigBuilder<TData, TType, TVal, TId> {
    const newInstance = this.clone();
    newInstance.config.meta = value;
    return newInstance;
  }

  private validateType(
    expectedTypes: ColumnDataType | ColumnDataType[],
    methodName: string,
  ) {
    const types = Array.isArray(expectedTypes)
      ? expectedTypes
      : [expectedTypes];
    if (!isAnyOf(this.config.type, types)) {
      throw new Error(
        `[Column config builder] ${methodName} is only applicable to ${types.join(" or ")} columns`,
      );
    }
  }

  build(): ColumnConfig<TData, TType, TVal, TId> {
    this.validateRequiredFields();
    return this.config as ColumnConfig<TData, TType, TVal, TId>;
  }

  private validateRequiredFields() {
    if (!this.config.id) throw new Error("id is required");
    if (!this.config.accessor) throw new Error("accessor is required");
    if (!this.config.displayName) throw new Error("displayName is required");
  }
}

// Update the helper interface
interface FluentColumnConfigHelper<TData> {
  text: () => ColumnConfigBuilder<TData, "text", string>;
  number: () => ColumnConfigBuilder<TData, "number", number>;
  bigint: () => ColumnConfigBuilder<TData, "bigint", bigint>;
  date: () => ColumnConfigBuilder<TData, "date", Date>;
  boolean: () => ColumnConfigBuilder<TData, "boolean", boolean>;
  option: () => ColumnConfigBuilder<TData, "option", string>;
  multiOption: () => ColumnConfigBuilder<TData, "multiOption", string[]>;
}

// Factory function remains mostly the same
export function createColumnConfigHelper<
  TData,
>(): FluentColumnConfigHelper<TData> {
  return {
    text: () => new ColumnConfigBuilder<TData, "text", string>("text"),
    number: () => new ColumnConfigBuilder<TData, "number", number>("number"),
    bigint: () => new ColumnConfigBuilder<TData, "bigint", bigint>("bigint"),
    date: () => new ColumnConfigBuilder<TData, "date", Date>("date"),
    boolean: () =>
      new ColumnConfigBuilder<TData, "boolean", boolean>("boolean"),
    option: () => new ColumnConfigBuilder<TData, "option", string>("option"),
    multiOption: () =>
      new ColumnConfigBuilder<TData, "multiOption", string[]>("multiOption"),
  };
}

import type {
  ColumnConfig,
  ColumnDataType,
  ColumnOption,
  ElementType,
  FilterStrategy,
  MinMaxReturn,
  Nullable,
  NumericValue,
} from "../types";
import { isAnyOf, minMax, uniq } from "../../lib/array";
import { isColumnOptionArray } from "../../lib/helpers";
import { memo } from "../../lib/memo";
import { applyOrderFns } from "../../lib/order-fns";

/**
 * Consolidated service for handling all column data operations including:
 * - Computing column options
 * - Getting column values
 * - Computing faceted unique values
 * - Computing faceted min/max values
 *
 * This centralizes the logic that was previously scattered across utils.ts and column-factory.ts
 */
export class ColumnDataService<TData> {
  constructor(
    private data: TData[],
    private strategy: FilterStrategy,
  ) {}

  /**
   * Step 1: Computes base column options without counts, ordering, or transforms
   */
  computeBaseOptions<TType extends ColumnDataType, TVal>(
    column: ColumnConfig<TData, TType, TVal>,
  ): ColumnOption[] {
    if (!isAnyOf(column.type, ["option", "multiOption"])) {
      return [];
    }

    if (this.strategy === "server" && !column.options) {
      throw new Error("column options are required for server-side filtering");
    }

    // If static options are provided, use them as the base
    if (column.options) {
      return column.options;
    }

    // Compute options from data
    const filtered = this.data
      .flatMap(column.accessor)
      .filter((v): v is NonNullable<TVal> => v !== undefined && v !== null);

    const uniqueValues = uniq(filtered);
    let columnOptions: ColumnOption[] = [];

    // Transform individual values to options
    if (column.transformValueToOptionFn) {
      columnOptions = uniqueValues.map((m) =>
        column.transformValueToOptionFn!(m as ElementType<NonNullable<TVal>>),
      );
    }

    if (isColumnOptionArray(columnOptions)) {
      return columnOptions;
    }

    throw new Error(
      `[data-table-filter] [${column.id}] Either provide static options, a transformValueToOptionFn, or ensure the column data conforms to ColumnOption type`,
    );
  }

  /**
   * Step 2: Computes ordered options with counts applied
   */
  computeOrderedOptions<TType extends ColumnDataType, TVal>(
    column: ColumnConfig<TData, TType, TVal>,
  ): ColumnOption[] {
    const baseOptions = this.computeBaseOptions(column);
    const values = this.getValues(column);

    // Add counts to base options
    const facetedData = this.computeFacetedUniqueValues(column, values as any);
    const optionsWithCounts = baseOptions.map((option) => ({
      ...option,
      count: facetedData?.get(option.value) || 0,
    }));

    // Apply ordering if provided
    if (column.orderFn) {
      return applyOrderFns(column.orderFn, optionsWithCounts);
    }

    return optionsWithCounts;
  }

  /**
   * Step 3: Computes final transformed options
   */
  computeTransformedOptions<TType extends ColumnDataType, TVal>(
    column: ColumnConfig<TData, TType, TVal>,
  ): ColumnOption[] {
    const orderedOptions = this.computeOrderedOptions(column);

    if (!column.transformOptionsFn) return orderedOptions;
    return column.transformOptionsFn(orderedOptions);
  }

  /**
   * Gets raw column values for processing
   */
  getValues<TType extends ColumnDataType, TVal>(
    column: ColumnConfig<TData, TType, TVal>,
  ): ElementType<NonNullable<TVal>>[] {
    // Memoize accessor calls
    const memoizedAccessor = memo(
      () => [this.data],
      (deps) =>
        (deps[0] ?? [])
          .flatMap(column.accessor)
          .filter(
            (v): v is NonNullable<TVal> => v !== undefined && v !== null,
          ) as ElementType<NonNullable<TVal>>[],
      { key: `accessor-${column.id}` },
    );

    const raw = memoizedAccessor();

    if (!isAnyOf(column.type, ["option", "multiOption"])) {
      return raw;
    }

    if (column.options) {
      return raw
        .map((v) => column.options?.find((o) => o.value === v)?.value)
        .filter((v) => v !== undefined && v !== null) as ElementType<
        NonNullable<TVal>
      >[];
    }

    if (column.transformValueToOptionFn) {
      const memoizedTransform = memo(
        () => [raw],
        (deps) =>
          (deps[0] ?? []).map(
            (v) =>
              column.transformValueToOptionFn!(v) as ElementType<
                NonNullable<TVal>
              >,
          ),
        { key: `transform-values-${column.id}` },
      );
      return memoizedTransform();
    }

    if (isColumnOptionArray(raw)) {
      return raw;
    }

    throw new Error(
      `[data-table-filter] [${column.id}] Either provide static options, a transformValueToOptionFn, or ensure the column data conforms to ColumnOption type`,
    );
  }

  /**
   * Computes faceted unique values for option-based columns
   */
  computeFacetedUniqueValues<TType extends ColumnDataType, TVal>(
    column: ColumnConfig<TData, TType, TVal>,
    values: string[] | ColumnOption[],
  ): Map<string, number> | undefined {
    if (!isAnyOf(column.type, ["option", "multiOption"])) {
      console.warn(
        "Faceted unique values can only be retrieved for option and multiOption columns",
      );
      return new Map<string, number>();
    }

    if (this.strategy === "server") {
      return column.facetedOptions;
    }

    const acc = new Map<string, number>();

    if (isColumnOptionArray(values)) {
      for (const option of values) {
        const curr = acc.get(option.value) ?? 0;
        acc.set(option.value, curr + 1);
      }
    } else {
      for (const option of values) {
        const curr = acc.get(option as string) ?? 0;
        acc.set(option as string, curr + 1);
      }
    }

    return acc;
  }

  /**
   * Computes faceted min/max values for number/bigint columns
   */
  computeFacetedMinMaxValues<TType extends ColumnDataType, TVal>(
    column: ColumnConfig<TData, TType, TVal>,
  ): MinMaxReturn<TType> {
    if (!isAnyOf(column.type, ["number", "bigint"])) {
      return undefined as MinMaxReturn<TType>;
    }

    // Check for static min/max values
    if (column.min !== undefined && column.max !== undefined) {
      return [column.min, column.max] as MinMaxReturn<TType>;
    }

    if (this.strategy === "server") {
      return undefined as MinMaxReturn<TType>;
    }

    // Extract values using the accessor
    const rawValues = this.data
      .flatMap((row) => column.accessor(row) as Nullable<NumericValue>)
      .filter(
        (v): v is NumericValue =>
          (typeof v === "number" && !Number.isNaN(v)) || typeof v === "bigint",
      );

    if (rawValues.length === 0) {
      const defaultValue = column.type === "bigint" ? [0n, 0n] : [0, 0];
      return defaultValue as MinMaxReturn<TType>;
    }

    // Filter to ensure type consistency
    if (column.type === "number") {
      const numberValues = rawValues.filter(
        (v): v is number => typeof v === "number",
      );
      return minMax(numberValues) as MinMaxReturn<TType>;
    }
    const bigintValues = rawValues.filter(
      (v): v is bigint => typeof v === "bigint",
    );
    return minMax(bigintValues) as MinMaxReturn<TType>;
  }
}

import type {
  Column,
  ColumnConfig,
  ColumnDataType,
  ElementType,
  FilterStrategy,
} from "../types";
import { memo } from "../../lib/memo";
import { ColumnDataService } from "./column-data-service";

export function createColumns<TData>(
  data: TData[],
  columnConfigs: ReadonlyArray<ColumnConfig<TData, any, any, any>>,
  strategy: FilterStrategy,
): Column<TData>[] {
  return columnConfigs.map((columnConfig) =>
    createColumn(columnConfig, data, strategy),
  );
}

export function createColumn<TData>(
  columnConfig: ColumnConfig<TData, any, any, any>,
  data: TData[],
  strategy: FilterStrategy,
): Column<TData> {
  // Create the centralized data service
  const dataService = new ColumnDataService(data, strategy);

  // Create memoized functions
  const getValues = createMemoizedValues(columnConfig, dataService);
  const getUniqueValues = createMemoizedUniqueValues(
    columnConfig,
    dataService,
    getValues,
  );
  const getMinMaxValues = createMemoizedMinMaxValues(columnConfig, dataService);

  // Create the main getOptions function that handles all transforms
  const getOptions = createMemoizedOptions(
    columnConfig,
    dataService,
    getValues,
  );

  // Create the Column instance
  const column: Column<TData> = {
    ...columnConfig,
    getOptions, // This now returns fully processed options
    getValues,
    getFacetedUniqueValues: getUniqueValues,
    getFacetedMinMaxValues: getMinMaxValues,
    // Prefetch methods will be added below
    prefetchOptions: async () => {}, // Placeholder, defined below
    prefetchValues: async () => {},
    prefetchFacetedUniqueValues: async () => {},
    prefetchFacetedMinMaxValues: async () => {},
    _prefetchedOptionsCache: null, // Initialize private cache
    _prefetchedValuesCache: null,
    _prefetchedFacetedUniqueValuesCache: null,
    _prefetchedFacetedMinMaxValuesCache: null,
  };

  if (strategy === "client") {
    // Define prefetch methods with access to the column instance
    setupPrefetchMethods(column, {
      getOptions,
      getValues,
      getUniqueValues,
      getMinMaxValues,
    });
  }

  return column;
}

/**
 * Creates the main getOptions function that returns fully processed options.
 * This includes all transforms and post-processing, plus automatic count population.
 */
function createMemoizedOptions<TData>(
  columnConfig: ColumnConfig<TData, any, any, any>,
  dataService: ColumnDataService<TData>,
  getValues: () => ElementType<NonNullable<any>>[],
) {
  return memo(
    () => [
      dataService,
      columnConfig.options,
      columnConfig.transformValueToOptionFn,
      columnConfig.transformOptionsFn,
      columnConfig.orderFn,
      getValues(), // Include values as dependency for reactivity
    ],
    () => {
      return dataService.computeTransformedOptions(columnConfig);
    },
    { key: `final-options-${columnConfig.id}` },
  );
}

function createMemoizedValues<TData>(
  columnConfig: ColumnConfig<TData, any, any, any>,
  dataService: ColumnDataService<TData>,
) {
  return memo(
    () => [dataService],
    ([dataService]) => dataService.getValues(columnConfig),
    { key: `values-${columnConfig.id}` },
  );
}

function createMemoizedUniqueValues<TData>(
  columnConfig: ColumnConfig<TData, any, any, any>,
  dataService: ColumnDataService<TData>,
  getValues: () => ElementType<NonNullable<any>>[],
) {
  return memo(
    () => [getValues(), dataService],
    ([values, dataService]) =>
      dataService.computeFacetedUniqueValues(columnConfig, values as any),
    { key: `faceted-${columnConfig.id}` },
  );
}

function createMemoizedMinMaxValues<TData, TType extends ColumnDataType>(
  columnConfig: ColumnConfig<TData, TType, any, any>,
  dataService: ColumnDataService<TData>,
) {
  return memo(
    () => [dataService],
    ([dataService]) => dataService.computeFacetedMinMaxValues(columnConfig),
    { key: `minmax-${columnConfig.id}` },
  );
}

function setupPrefetchMethods<TData>(
  column: Column<TData>,
  methods: {
    getOptions: () => any;
    getValues: () => any;
    getUniqueValues: () => any;
    getMinMaxValues: () => any;
  },
) {
  const { getOptions, getValues, getUniqueValues, getMinMaxValues } = methods;

  column.prefetchOptions = async (): Promise<void> => {
    if (!column._prefetchedOptionsCache) {
      await new Promise((resolve) =>
        setTimeout(() => {
          column._prefetchedOptionsCache = getOptions();
          resolve(undefined);
        }, 0),
      );
    }
  };

  column.prefetchValues = async (): Promise<void> => {
    if (!column._prefetchedValuesCache) {
      await new Promise((resolve) =>
        setTimeout(() => {
          column._prefetchedValuesCache = getValues();
          resolve(undefined);
        }, 0),
      );
    }
  };

  column.prefetchFacetedUniqueValues = async (): Promise<void> => {
    if (!column._prefetchedFacetedUniqueValuesCache) {
      await new Promise((resolve) =>
        setTimeout(() => {
          column._prefetchedFacetedUniqueValuesCache =
            getUniqueValues() ?? null;
          resolve(undefined);
        }, 0),
      );
    }
  };

  column.prefetchFacetedMinMaxValues = async (): Promise<void> => {
    if (!column._prefetchedFacetedMinMaxValuesCache) {
      await new Promise((resolve) =>
        setTimeout(() => {
          column._prefetchedFacetedMinMaxValuesCache =
            getMinMaxValues() ?? null;
          resolve(undefined);
        }, 0),
      );
    }
  };
}

import type { FilterModel } from "../../core/types";
import type { Row } from "@tanstack/react-table";
import * as f from "../../lib/filter-fns";

export function dateFilterFn<TData>(
  row: Row<TData>,
  columnId: string,
  filterValue: FilterModel<"date">,
): boolean {
  const value = row.getValue<Date>(columnId);

  return f.dateFilterFn(value, filterValue);
}

export function textFilterFn<TData>(
  row: Row<TData>,
  columnId: string,
  filterValue: FilterModel<"text">,
): boolean {
  const value = row.getValue<string>(columnId) ?? "";

  return f.textFilterFn(value, filterValue);
}

export function numberFilterFn<TData>(
  row: Row<TData>,
  columnId: string,
  filterValue: FilterModel<"number">,
): boolean {
  const value = row.getValue<number>(columnId);

  return f.numberFilterFn(value, filterValue);
}

export function booleanFilterFn<TData>(
  row: Row<TData>,
  columnId: string,
  filterValue: FilterModel<"boolean">,
): boolean {
  const value = row.getValue<boolean>(columnId) ?? false;

  return f.booleanFilterFn(value, filterValue);
}

import type { Column, FilterModel, FiltersState } from "../../core/types";
import type { ColumnDef, ColumnFiltersState } from "@tanstack/react-table";
import { multiOptionFilterFn, optionFilterFn } from "../../lib/filter-fns";
import {
  isColumnOption,
  isColumnOptionArray,
  isStringArray,
} from "../../lib/helpers";
import {
  booleanFilterFn,
  dateFilterFn,
  numberFilterFn,
  textFilterFn,
} from "./filter-fns";

interface CreateTSTColumns<TData> {
  columns: ColumnDef<TData, any>[];
  configs: Column<TData>[];
}

export function createTSTColumns<TData>({
  columns,
  configs,
}: CreateTSTColumns<TData>) {
  const _cols: ColumnDef<TData>[] = [];

  for (const col of columns) {
    // Get the column filter config for this column
    const config = configs.find((c) => c.id === col.id);

    // If the column is not filterable or doesn't have a filter config, skip it
    // An explicit check is done on `enableColumnFilter`
    if (col.enableColumnFilter === false || !config) {
      _cols.push(col);
      continue;
    }

    if (config.type === "text") {
      col.filterFn = textFilterFn;
      _cols.push(col);
      continue;
    }

    if (config.type === "number") {
      col.filterFn = numberFilterFn;
      _cols.push(col);
      continue;
    }

    if (config.type === "date") {
      col.filterFn = dateFilterFn;
      _cols.push(col);
      continue;
    }

    if (config.type === "boolean") {
      col.filterFn = booleanFilterFn;
      _cols.push(col);
      continue;
    }

    if (config.type === "option") {
      col.filterFn = (row, columnId, filterValue: FilterModel<"option">) => {
        const value = row.getValue<unknown>(columnId);

        if (!value) return false;

        if (typeof value === "string") {
          return optionFilterFn(value, filterValue);
        }

        if (isColumnOption(value)) {
          return optionFilterFn(value.value, filterValue);
        }

        const sanitizedValue = config.transformValueToOptionFn!(value as never);
        return optionFilterFn(sanitizedValue.value, filterValue);
      };
    }

    if (config.type === "multiOption") {
      col.filterFn = (
        row,
        columnId,
        filterValue: FilterModel<"multiOption">,
      ) => {
        const value = row.getValue(columnId);

        if (!value) return false;

        if (isStringArray(value)) {
          return multiOptionFilterFn(value, filterValue);
        }

        if (isColumnOptionArray(value)) {
          return multiOptionFilterFn(
            value.map((v) => v.value),
            filterValue,
          );
        }

        const sanitizedValue = (value as never[]).map((v) =>
          config.transformValueToOptionFn!(v),
        );

        return multiOptionFilterFn(
          sanitizedValue.map((v) => v.value),
          filterValue,
        );
      };
    }

    _cols.push(col);
  }

  return _cols;
}

export function createTSTFilters(filters: FiltersState): ColumnFiltersState {
  return filters.map((filter) => ({ id: filter.columnId, value: filter }));
}

import type { CxOptions } from "class-variance-authority";
import * as React from "react";
import { cx } from "class-variance-authority";
import { twMerge } from "tailwind-merge";

export const cn = (...inputs: CxOptions) => twMerge(cx(inputs));

/**
 * @see https://github.com/radix-ui/primitives/blob/main/packages/react/compose-refs/src/composeRefs.tsx
 */
type PossibleRef<T> = React.Ref<T> | undefined;

/**
 * Set a given ref to a given value
 * This utility takes care of different types of refs: callback refs and RefObject(s)
 */
function setRef<T>(ref: PossibleRef<T>, value: T) {
  if (typeof ref === "function") {
    ref(value);
  } else if (ref !== null && ref !== undefined) {
    (ref as React.MutableRefObject<T>).current = value;
  }
}

/**
 * A utility to compose multiple refs together
 * Accepts callback refs and RefObject(s)
 */
export function composeRefs<T>(...refs: PossibleRef<T>[]) {
  return (node: T) => refs.forEach((ref) => setRef(ref, node));
}

/**
 * A custom hook that composes multiple refs
 * Accepts callback refs and RefObject(s)
 */
export function useComposedRefs<T>(...refs: PossibleRef<T>[]) {
  // eslint-disable-next-line react-hooks/exhaustive-deps
  return React.useCallback(composeRefs(...refs), refs);
}

/**
 * @see https://github.com/radix-ui/primitives/blob/main/packages/react/use-callback-ref/src/useCallbackRef.tsx
 */
/**
 * A custom hook that converts a callback to a ref to avoid triggering re-renders when passed as a
 * prop or avoid re-executing effects when passed as a dependency
 */
export function useCallbackRef<T extends (...args: never[]) => unknown>(
  callback: T | undefined,
): T {
  const callbackRef = React.useRef(callback);

  React.useEffect(() => {
    callbackRef.current = callback;
  });

  // https://github.com/facebook/react/issues/19240
  return React.useMemo(
    () => ((...args) => callbackRef.current?.(...args)) as T,
    [],
  );
}

export function useDebounce<T>(value: T, delay?: number): T {
  const [debouncedValue, setDebouncedValue] = React.useState<T>(value);

  React.useEffect(() => {
    const timer = setTimeout(() => setDebouncedValue(value), delay ?? 500);

    return () => {
      clearTimeout(timer);
    };
  }, [value, delay]);

  return debouncedValue;
}

export function useDebouncedCallback<T extends (...args: never[]) => unknown>(
  callback: T,
  delay: number,
) {
  const handleCallback = useCallbackRef(callback);
  const debounceTimerRef = React.useRef(0);
  React.useEffect(
    () => () => window.clearTimeout(debounceTimerRef.current),
    [],
  );

  const setValue = React.useCallback(
    (...args: Parameters<T>) => {
      window.clearTimeout(debounceTimerRef.current);
      debounceTimerRef.current = window.setTimeout(
        () => handleCallback(...args),
        delay,
      );
    },
    [handleCallback, delay],
  );

  return setValue;
}

export function useMediaQuery(query = "(min-width: 640px)") {
  const [value, setValue] = React.useState(false);

  React.useEffect(() => {
    function onChange(event: MediaQueryListEvent) {
      setValue(event.matches);
    }

    const result = matchMedia(query);
    result.addEventListener("change", onChange);
    setValue(result.matches);

    return () => result.removeEventListener("change", onChange);
  }, [query]);

  return value;
}

export function formatDate(
  date: Date | string | number,
  opts: Intl.DateTimeFormatOptions = {},
) {
  return new Intl.DateTimeFormat("en-US", {
    month: opts.month ?? "long",
    day: opts.day ?? "numeric",
    year: opts.year ?? "numeric",
    ...opts,
  }).format(new Date(date));
}

const MOBILE_BREAKPOINT = 768;

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(
    undefined,
  );

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    };
    mql.addEventListener("change", onChange);
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    return () => mql.removeEventListener("change", onChange);
  }, []);

  return !!isMobile;
}

